/**
 * Add Institute Member Dialog — invite new member to admin group.
 *
 * Source: old AddInstituteMemberDialog.js → simplified.
 */

import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Loader2, UserPlus, Mail } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { post } from "@/shared/services/api-client";
import { API_PATHS } from "@/config/constants";

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------

interface AddInstituteMemberDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onAdded?: () => void;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function AddInstituteMemberDialog({
  open,
  onOpenChange,
  onAdded,
}: AddInstituteMemberDialogProps) {
  const { t } = useTranslation();
  const [email, setEmail] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);

  function reset() {
    setEmail("");
    setError("");
    setLoading(false);
    setSuccess(false);
  }

  async function handleSubmit() {
    if (!email.trim()) {
      setError("Email is required");
      return;
    }
    if (!/\S+@\S+\.\S+/.test(email)) {
      setError("Invalid email address");
      return;
    }

    setLoading(true);
    setError("");

    try {
      await post(`${API_PATHS.HOST}/admin-group/add-member`, { email });
      setSuccess(true);
      onAdded?.();
    } catch (err) {
      setError("Failed to add member. They may already be in the group.");
    }
    setLoading(false);
  }

  return (
    <Dialog
      open={open}
      onOpenChange={(v) => {
        if (!v) reset();
        onOpenChange(v);
      }}
    >
      <DialogContent className="sm:max-w-[400px]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <UserPlus className="h-5 w-5 text-link" />
            {t("add institute member - title") || "Add Institute Member"}
          </DialogTitle>
        </DialogHeader>

        {success ? (
          <div className="flex flex-col items-center gap-3 py-6">
            <Mail className="h-10 w-10 text-green-500" />
            <p className="text-sm text-gray-700 text-center">
              Invitation sent to <span className="font-medium">{email}</span>
            </p>
          </div>
        ) : (
          <div className="space-y-4 py-2">
            <p className="text-sm text-gray-500">
              Enter the email address of the host you want to add to your
              institute group.
            </p>
            <div className="space-y-1.5">
              <Label htmlFor="member-email">Email Address</Label>
              <Input
                id="member-email"
                type="email"
                value={email}
                onChange={(e) => {
                  setEmail(e.target.value);
                  setError("");
                }}
                placeholder="host@university.edu"
                className={error ? "border-red-400" : ""}
              />
              {error && <p className="text-xs text-red-500">{error}</p>}
            </div>
          </div>
        )}

        <DialogFooter>
          {success ? (
            <Button onClick={() => onOpenChange(false)}>Done</Button>
          ) : (
            <>
              <Button
                variant="ghost"
                className="text-[#333] hover:bg-gray-100"
                onClick={() => onOpenChange(false)}
                disabled={loading}
              >
                Cancel
              </Button>
              <Button
                onClick={handleSubmit}
                disabled={loading}
                className="bg-link hover:bg-link/90 text-white"
              >
                {loading ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <span className="flex items-center gap-1">
                    <UserPlus className="h-4 w-4" /> Add Member
                  </span>
                )}
              </Button>
            </>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useEffect } from "react";
import { useTranslation } from "react-i18next";
import { format, parseISO, startOfWeek, endOfWeek } from "date-fns";
import { useNavigate, useSearch } from "@tanstack/react-router";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from "recharts";

import { useAdminStore } from "../store/admin.store";
import { ADMIN_VIEWS } from "@/config/constants";
import type { AdminView } from "@/config/constants";

export function AdminDashboardGraph() {
  const { t } = useTranslation();
  const {
    adminStats,
    view,
    changeView,
    viewType,
    dates,
    changeViewType,
    elementsView,
    setElementsView,
    setDates,
    selectedGraphItems,
  } = useAdminStore();

  const navigate = useNavigate();
  const search: Record<string, any> = useSearch({ strict: false });

  // Sync URL view to store on load/change
  useEffect(() => {
    const desiredView = (search.view as AdminView) || ADMIN_VIEWS.MAIN_DASHBOARD;
    if (desiredView !== view) {
      changeView(desiredView);
    }
  }, [search.view, view, changeView]);

  const handleDropdownChange = (newView: string) => {
    changeView(newView as AdminView);
    navigate({
      to: "/admin",
      search: (prev: Record<string, any>) => ({ ...prev, view: newView }),
    });
  };

  const graphData = (adminStats as Record<string, any>)?.generalGraph || [];
  const fieldGraph = (adminStats as Record<string, any>)?.fieldGraph || [];

  const defaultTo = endOfWeek(new Date());
  const defaultFrom = new Date(
    defaultTo.getFullYear(),
    defaultTo.getMonth() - 5,
    1,
  );

  const fromDate = dates?.from ? parseISO(dates.from) : defaultFrom;
  const toDate = dates?.to ? parseISO(dates.to) : defaultTo;

  // Re-create the legacy getWeek function to perfectly match backend _id
  function getLegacyWeek(d: Date) {
    const target = new Date(d.valueOf());
    const dayNr = (target.getDay() + 6) % 7;
    target.setDate(target.getDate() - dayNr + 3);
    const firstThursday = target.valueOf();
    target.setMonth(0, 1);
    if (target.getDay() !== 4) {
      target.setMonth(0, 1 + ((4 - target.getDay() + 7) % 7));
    }
    return 1 + Math.ceil((firstThursday - target.getTime()) / 604800000);
  }

  const isDayView = viewType.datesType === "DAY";
  const data = [];

  let deltaInDays =
    (toDate.getTime() - fromDate.getTime()) / (1000 * 3600 * 24);
  if (!isDayView) {
    deltaInDays += fromDate.getDay();
  }

  const datesJump = isDayView ? 1 : 7;

  for (let i = 0; i <= deltaInDays; i += datesJump) {
    let date = new Date(fromDate);
    let lookupId = "";
    let displayLabel = "";

    if (isDayView) {
      date.setDate(date.getDate() + i);
      lookupId = format(date, "MM dd yyyy");
      displayLabel = format(date, "MMM dd yyyy");
    } else {
      date.setDate(date.getDate() + i - date.getDay() + 2);
      const week = getLegacyWeek(date);
      const year = date.getFullYear();

      lookupId = `${year}-${week}`;

      const labelDate = new Date(fromDate);
      labelDate.setHours(0, 0, 0, 0);
      labelDate.setDate(labelDate.getDate() + i);
      const startOfWeekDate = new Date(labelDate);
      startOfWeekDate.setDate(labelDate.getDate() - labelDate.getDay());
      displayLabel = format(startOfWeekDate, "MMM dd yyyy");
    }

    const point = graphData.find(
      (p: Record<string, any>) => p._id === lookupId || p.id === lookupId,
    );
    let value = 0;
    if (point) {
      value =
        viewType.dataType === "PERCENT"
          ? Math.floor((point.rate || 0) * 1000) / 10
          : point.checkins || 0;
    }

    const dataPoint: Record<string, any> = {
      name: displayLabel,
      value, // Always 'value' for average/overall
    };

    // Process fieldGraph for selected faculties
    if (fieldGraph && fieldGraph.length > 0) {
      fieldGraph.forEach((facultyItem: Record<string, any>) => {
        if (selectedGraphItems.includes(facultyItem.itemId)) {
          let count = 0;
          let rate = 0;
          let checkins = 0;
          facultyItem.dates?.forEach((d: Record<string, any>) => {
            if (d.date === lookupId) {
              count++;
              rate += d.rate;
              checkins += d.checkins;
            }
          });

          let facultyValue = 0;
          if (count > 0) {
            facultyValue =
              viewType.dataType === "PERCENT"
                ? Math.floor((rate / count) * 1000) / 10
                : checkins;
          }
          dataPoint[`val_${facultyItem.itemId}`] = facultyValue;
        }
      });
    }

    data.push(dataPoint);
  }

  const yAxisDomain =
    viewType.dataType === "PERCENT" ? [0, 100] : ["auto", "auto"];
  const yAxisTickFormatter = (val: number) =>
    viewType.dataType === "PERCENT" ? `${val}%` : val.toString();

  const fromStr = dates?.from
    ? format(parseISO(dates.from), "yyyy-MM-dd")
    : format(defaultFrom, "yyyy-MM-dd");
  const toStr = dates?.to
    ? format(parseISO(dates.to), "yyyy-MM-dd")
    : format(defaultTo, "yyyy-MM-dd");

  // A static palette of 10 nice distinct colors, similar to config.admin.colors in legacy
  const COLORS = [
    "#F44336",
    "#9C27B0",
    "#E91E63",
    "#673AB7",
    "#3F51B5",
    "#00BCD4",
    "#009688",
    "#4CAF50",
    "#8BC34A",
    "#FF9800",
  ];

  return (
    <div className="bg-white rounded-md shadow-sm border border-gray-200 flex flex-col overflow-hidden">
      {/* Top Control Bar */}
      <div className="flex flex-wrap items-center justify-between p-4 bg-white border-b border-gray-200 gap-4">
        {/* Left Side: Select & Checkboxes */}
        <div className="flex items-center gap-6">
          <select
            value={search.view || view}
            onChange={(e) => handleDropdownChange(e.target.value)}
            className="bg-white border border-gray-300 text-gray-900 text-sm rounded focus:ring-blue-500 focus:border-blue-500 block w-48 p-2 cursor-pointer shadow-sm"
          >
            <option value={ADMIN_VIEWS.MAIN_DASHBOARD}>Academic Units</option>
            <option value={ADMIN_VIEWS.MAIN_DASHBOARD_COURSES}>Courses</option>
            <option value={ADMIN_VIEWS.MAIN_DASHBOARD_HOSTS}>
              Instructors
            </option>
          </select>

          <div className="flex items-center gap-4 text-sm font-medium text-gray-700">
            <label className="flex items-center gap-1.5 cursor-pointer">
              <input
                type="checkbox"
                checked={elementsView.adminMainGraphShow}
                onChange={(e) =>
                  setElementsView({
                    ...elementsView,
                    adminMainGraphShow: e.target.checked,
                  })
                }
                className="w-4 h-4 text-[#039be5] bg-gray-100 border-gray-300 rounded focus:ring-[#039be5]"
              />
              Graph
            </label>
            <label className="flex items-center gap-1.5 cursor-pointer">
              <input
                type="checkbox"
                checked={elementsView.adminMainStatsShow}
                onChange={(e) =>
                  setElementsView({
                    ...elementsView,
                    adminMainStatsShow: e.target.checked,
                  })
                }
                className="w-4 h-4 text-[#039be5] bg-gray-100 border-gray-300 rounded focus:ring-[#039be5]"
              />
              Overall
            </label>
            <label className="flex items-center gap-1.5 cursor-pointer">
              <input
                type="checkbox"
                checked={elementsView.adminMainTableShow}
                onChange={(e) =>
                  setElementsView({
                    ...elementsView,
                    adminMainTableShow: e.target.checked,
                  })
                }
                className="w-4 h-4 text-blue-600 bg-gray-100 border-gray-300 rounded focus:ring-blue-500"
              />
              List
            </label>
          </div>
        </div>

        {/* Right Side: Toggle Switch & Dates */}
        <div className="flex items-center gap-6">
          <div className="flex items-center bg-transparent rounded-md p-0.5 border border-[#039be5]">
            <button
              onClick={() => changeViewType({ dataType: "PERCENT" })}
              className={`px-4 py-1.5 text-sm font-medium transition-colors ${viewType.dataType === "PERCENT" ? "bg-[#039be5] text-white" : "text-[#039be5] bg-white hover:bg-blue-50"}`}
            >
              Percent
            </button>
            <button
              onClick={() => changeViewType({ dataType: "COUNT" })}
              className={`px-4 py-1.5 text-sm font-medium transition-colors ${viewType.dataType === "COUNT" ? "bg-[#039be5] text-white" : "text-[#039be5] bg-white hover:bg-blue-50"}`}
            >
              Check-ins
            </button>
          </div>

          <div className="flex items-center gap-6">
            <div className="flex flex-col">
              <span className="text-xs text-gray-500 mb-0.5 cursor-default">
                Start week
              </span>
              <input
                type="date"
                value={fromStr}
                onChange={(e) => {
                  if (!e.target.value) return;
                  const selected = parseISO(e.target.value);
                  const snapped = startOfWeek(selected);
                  setDates({ from: format(snapped, "yyyy-MM-dd"), to: toStr });
                }}
                className="text-sm font-medium text-gray-800 border-b border-gray-400 pb-0.5 min-w-[130px] bg-transparent outline-none cursor-pointer focus:border-blue-500 transition-colors"
                max={toStr}
              />
            </div>
            <div className="flex flex-col">
              <span className="text-xs text-gray-500 mb-0.5 cursor-default">
                End week
              </span>
              <input
                type="date"
                value={toStr}
                onChange={(e) => {
                  if (!e.target.value) return;
                  const selected = parseISO(e.target.value);
                  const snapped = endOfWeek(selected);
                  setDates({
                    from: fromStr,
                    to: format(snapped, "yyyy-MM-dd"),
                  });
                }}
                className="text-sm font-medium text-gray-800 border-b border-gray-400 pb-0.5 min-w-[130px] bg-transparent outline-none cursor-pointer focus:border-blue-500 transition-colors"
                min={fromStr}
                max={format(new Date(), "yyyy-MM-dd")}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Chart Area */}
      {elementsView.adminMainGraphShow && (
        <div className="h-[400px] w-full p-4 relative flex flex-col items-center justify-center">
          {data.length === 0 ? (
            <p className="text-gray-500 font-medium text-lg">
              {t("No graph data available for the selected dates.")}
            </p>
          ) : (
            <>
              <div className="absolute top-6 left-12">
                <span className="text-xs font-medium text-gray-500">
                  {viewType.dataType === "PERCENT" ? "100" : ""}
                </span>
              </div>
              <ResponsiveContainer
                width="100%"
                height="100%"
                className="border border-gray-300 mt-2 bg-[#fcfcfc]"
              >
                <LineChart
                  data={data}
                  margin={{ top: 20, right: 30, left: 0, bottom: 20 }}
                >
                  <CartesianGrid
                    strokeDasharray="0"
                    vertical={true}
                    stroke="#e0e0e0"
                  />
                  <XAxis
                    dataKey="name"
                    axisLine={false}
                    tickLine={false}
                    tick={{ fontSize: 11, fill: "#888888" }}
                    dy={10}
                  />
                  <YAxis
                    axisLine={false}
                    tickLine={false}
                    domain={yAxisDomain}
                    tickFormatter={yAxisTickFormatter}
                    tick={{ fontSize: 11, fill: "#888888" }}
                    dx={-10}
                  />
                  <Tooltip
                    contentStyle={{
                      borderRadius: "4px",
                      border: "1px solid #E5E7EB",
                      boxShadow: "0 2px 4px -1px rgba(0, 0, 0, 0.1)",
                    }}
                    formatter={(value: number | string | undefined) => {
                      if (value === undefined) return ["", ""];
                      return [
                        viewType.dataType === "PERCENT" ? `${value}%` : value,
                        viewType.dataType === "PERCENT"
                          ? t("Average")
                          : t("Check-ins"),
                      ];
                    }}
                  />
                  {selectedGraphItems.includes("all") && (
                    <Line
                      type="monotone"
                      dataKey="value"
                      name={t("Average")}
                      stroke={
                        viewType.dataType === "PERCENT" ? "#000000" : "#2563EB"
                      }
                      strokeWidth={2.2}
                      dot={{ r: 2, strokeWidth: 2, fill: "#fff" }}
                      activeDot={{
                        r: 4,
                        strokeWidth: 0,
                        fill:
                          viewType.dataType === "PERCENT"
                            ? "#000000"
                            : "#2563EB",
                      }}
                    />
                  )}
                  {fieldGraph.map((item: Record<string, any>, index: number) => {
                    if (!selectedGraphItems.includes(item.itemId)) return null;
                    return (
                      <Line
                        key={item.itemId}
                        type="monotone"
                        dataKey={`val_${item.itemId}`}
                        name={item.itemName || "Unknown"}
                        stroke={COLORS[index % COLORS.length]}
                        strokeWidth={2}
                        dot={{ r: 2, strokeWidth: 2, fill: "#fff" }}
                        activeDot={{
                          r: 4,
                          strokeWidth: 0,
                          fill: COLORS[index % COLORS.length],
                        }}
                      />
                    );
                  })}
                </LineChart>
              </ResponsiveContainer>
            </>
          )}
        </div>
      )}
    </div>
  );
}

import { useTranslation } from "react-i18next";
import { useAdminStore } from "../store/admin.store";
import { useState, useMemo } from "react";
import { format } from "date-fns";
import { FileSpreadsheet, ChevronLeft, ChevronRight } from "lucide-react";

export function AdminFieldStatsTable() {
  const { t } = useTranslation();
  const { adminStats, loading, selectedGraphItems, toggleGraphItem } =
    useAdminStore();

  const fieldData = (adminStats as Record<string, any>)?.field || [];
  const generalData = (adminStats as Record<string, any>)?.general || {};

  const [sortConfig, setSortConfig] = useState<{
    key: string;
    direction: "asc" | "desc";
  } | null>(null);

  const [minCourses, setMinCourses] = useState<number | "">("");
  const [minSessions, setMinSessions] = useState<number | "">("");
  const [minAttendees, setMinAttendees] = useState<number | "">("");
  const [minCheckins, setMinCheckins] = useState<number | "">("");

  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(25);

  const requestSort = (key: string) => {
    let direction: "asc" | "desc" = "asc";
    if (
      sortConfig &&
      sortConfig.key === key &&
      sortConfig.direction === "asc"
    ) {
      direction = "desc";
    }
    setSortConfig({ key, direction });
  };

  const filteredData = useMemo(() => {
    return fieldData.filter((a: Record<string, any>) => {
      if (minCourses !== "" && (a.courses?.length || 0) < minCourses)
        return false;
      if (minSessions !== "" && (a.sessions || 0) < minSessions) return false;
      if (minAttendees !== "" && (a.activeAttendees || 0) < minAttendees)
        return false;
      if (minCheckins !== "" && (a.checkins || 0) < minCheckins) return false;
      return true;
    });
  }, [fieldData, minCourses, minSessions, minAttendees, minCheckins]);

  const sortedData = useMemo(() => {
    const sortableItems = [...filteredData];
    if (sortConfig !== null) {
      sortableItems.sort((a: Record<string, any>, b: Record<string, any>) => {
        let aVal: string | number = 0;
        let bVal: string | number = 0;

        switch (sortConfig.key) {
          case "name":
            aVal = a.faculty?.name || "";
            bVal = b.faculty?.name || "";
            break;
          case "rate":
            aVal = Math.floor((a.rate || 0) * 1000) / 10;
            bVal = Math.floor((b.rate || 0) * 1000) / 10;
            break;
          case "courses":
            aVal = a.courses?.length || 0;
            bVal = b.courses?.length || 0;
            break;
          default:
            aVal = a[sortConfig.key] || 0;
            bVal = b[sortConfig.key] || 0;
        }

        if (aVal < bVal) return sortConfig.direction === "asc" ? -1 : 1;
        if (aVal > bVal) return sortConfig.direction === "asc" ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [filteredData, sortConfig]);

  const paginatedData = useMemo(() => {
    const start = page * rowsPerPage;
    return sortedData.slice(start, start + rowsPerPage);
  }, [sortedData, page, rowsPerPage]);

  const totalPages = Math.ceil(sortedData.length / rowsPerPage);

  const handleExportExcel = async () => {
    const ExcelJS = (await import("exceljs")).default;
    const fileSaver = await import("file-saver");
    const saveAs = fileSaver.saveAs || fileSaver.default;

    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet("Report");

    sheet.addRow([
      t("Academic Unit"),
      t("Attendance Rate"),
      t("Courses"),
      t("Sessions"),
      t("Unique Attendees"),
      t("Check-ins"),
    ]);

    const len = fieldData.length || 1;
    sheet.addRow([
      "Average",
      generalData.avgAttendanceRate !== undefined
        ? Math.floor(generalData.avgAttendanceRate * 1000) / 10 + "%"
        : "",
      Math.round((generalData.courses || 0) / len),
      Math.round((generalData.sessions || 0) / len),
      Math.round(
        fieldData.reduce(
          (acc: number, r: Record<string, any>) => acc + (r.activeAttendees || 0),
          0,
        ) / len,
      ),
      Math.round((generalData.checkins || 0) / len),
    ]);

    sortedData.forEach((row: Record<string, any>, i: number) => {
      sheet.addRow([
        i + 1,
        row.faculty?.name || "Unknown",
        `${Math.floor((row.rate || 0) * 1000) / 10}%`,
        row.courses?.length || 0,
        row.sessions || 0,
        row.activeAttendees || 0,
        row.checkins || 0,
      ]);
    });

    sheet.getRow(1).font = { bold: true };
    sheet.getRow(1).fill = {
      type: "pattern",
      pattern: "solid",
      fgColor: { argb: "FFF2F2F2" },
      bgColor: { argb: "FFF2F2F2" },
    };
    sheet.columns.forEach((col) => {
      if (col) col.width = 20;
    });

    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], {
      type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
    });
    saveAs(blob, `Report_${format(new Date(), "yyyy-MM-dd")}.xlsx`);
  };

  if (loading) {
    return (
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 mt-6 overflow-hidden">
        <div className="h-[400px] animate-pulse bg-gray-50 flex flex-col">
          <div className="h-12 bg-gray-200 border-b border-gray-200" />
          {[1, 2, 3, 4, 5].map((i) => (
            <div key={i} className="h-12 bg-gray-100 mt-2 mx-4 rounded" />
          ))}
        </div>
      </div>
    );
  }

  if (!fieldData.length && !loading) {
    return null;
  }

  return (
    <div className="bg-white rounded-xl shadow-[0_0_1px_0_rgba(0,0,0,0.24)] border border-black/20 overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left whitespace-nowrap">
          <thead>
            <tr className="border-b border-gray-300 bg-[#f5f5f5] text-gray-800 font-semibold">
              <th className="px-6 py-4 w-12 text-center">
                <input
                  type="checkbox"
                  className="rounded border-gray-300 cursor-pointer"
                  checked={
                    selectedGraphItems.includes("all") &&
                    fieldData.every((r: Record<string, any>) =>
                      selectedGraphItems.includes(
                        r.faculty?._id || r.faculty?.id,
                      ),
                    )
                  }
                  onChange={(e) => {
                    const isChecked = e.target.checked;
                    toggleGraphItem("all", true);
                    // Also toggle all rows if "all" is clicked (optional behavior, but typical)
                    if (isChecked) {
                      fieldData.forEach((r: Record<string, any>) => {
                        const id = r.faculty?._id || r.faculty?.id;
                        if (id && !selectedGraphItems.includes(id))
                          toggleGraphItem(id);
                      });
                    } else {
                      fieldData.forEach((r: Record<string, any>) => {
                        const id = r.faculty?._id || r.faculty?.id;
                        if (id && selectedGraphItems.includes(id))
                          toggleGraphItem(id);
                      });
                    }
                  }}
                />
              </th>
              <th
                className="px-6 py-4 cursor-pointer hover:bg-[#ebebeb]"
                onClick={() => requestSort("name")}
              >
                {t("Academic Unit")}{" "}
                {sortConfig?.key === "name"
                  ? sortConfig.direction === "asc"
                    ? "↑"
                    : "↓"
                  : ""}
              </th>
              <th
                className="px-6 py-4 cursor-pointer hover:bg-[#ebebeb]"
                onClick={() => requestSort("rate")}
              >
                {t("Attendance Rate")}{" "}
                {sortConfig?.key === "rate"
                  ? sortConfig.direction === "asc"
                    ? "↑"
                    : "↓"
                  : ""}
              </th>
              <th
                className="px-6 py-4 cursor-pointer hover:bg-[#ebebeb]"
                onClick={() => requestSort("courses")}
              >
                {t("Courses")}{" "}
                {sortConfig?.key === "courses"
                  ? sortConfig.direction === "asc"
                    ? "↑"
                    : "↓"
                  : ""}
              </th>
              <th
                className="px-6 py-4 cursor-pointer hover:bg-[#ebebeb]"
                onClick={() => requestSort("sessions")}
              >
                {t("Sessions")}{" "}
                {sortConfig?.key === "sessions"
                  ? sortConfig.direction === "asc"
                    ? "↑"
                    : "↓"
                  : ""}
              </th>
              <th
                className="px-6 py-4 cursor-pointer hover:bg-[#ebebeb]"
                onClick={() => requestSort("activeAttendees")}
              >
                {t("Unique Attendees")}{" "}
                {sortConfig?.key === "activeAttendees"
                  ? sortConfig.direction === "asc"
                    ? "↑"
                    : "↓"
                  : ""}
              </th>
              <th
                className="px-6 py-4 cursor-pointer hover:bg-[#ebebeb]"
                onClick={() => requestSort("checkins")}
              >
                {t("Check-ins")}{" "}
                {sortConfig?.key === "checkins"
                  ? sortConfig.direction === "asc"
                    ? "↑"
                    : "↓"
                  : ""}
              </th>
              <th className="px-6 py-2 text-right">
                <div className="flex items-center justify-end gap-3">
                  <button
                    onClick={handleExportExcel}
                    className="p-1 hover:bg-gray-200 rounded transition-colors"
                    title="Export to XLS"
                  >
                    <FileSpreadsheet className="w-5 h-5 text-emerald-600" />
                  </button>
                </div>
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100 text-gray-700">
            {/* Overall Row */}
            <tr className="bg-gray-50/60 font-medium text-gray-900">
              <td className="px-6 py-3 text-center">
                <input
                  type="checkbox"
                  className="rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
                  checked={selectedGraphItems.includes("all")}
                  onChange={() => toggleGraphItem("all", true)}
                />
              </td>
              <td className="px-6 py-3">Average</td>
              <td className="px-6 py-3">
                {generalData.avgAttendanceRate !== undefined
                  ? Math.floor(generalData.avgAttendanceRate * 1000) / 10 + "%"
                  : ""}
              </td>
              <td className="px-6 py-3">
                {Math.round(
                  (generalData.courses || 0) / (fieldData.length || 1),
                )}
              </td>
              <td className="px-6 py-3">
                {Math.round(
                  (generalData.sessions || 0) / (fieldData.length || 1),
                )}
              </td>
              <td className="px-6 py-3">
                {Math.round(
                  fieldData.reduce(
                    (acc: number, r: Record<string, any>) => acc + (r.activeAttendees || 0),
                    0,
                  ) / (fieldData.length || 1),
                )}
              </td>
              <td className="px-6 py-3">
                {Math.round(
                  (generalData.checkins || 0) / (fieldData.length || 1),
                )}
              </td>
              <td className="px-6 py-3"></td>
            </tr>

            {/* Sorted Items */}
            {paginatedData.map((row: Record<string, any>, index: number) => {
              return (
                <tr
                  key={index}
                  className="hover:bg-gray-50/80 transition-colors"
                >
                  <td className="px-6 py-3 text-center">
                    <input
                      type="checkbox"
                      className="rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
                      checked={selectedGraphItems.includes(
                        row.faculty?._id || row.faculty?.id,
                      )}
                      onChange={() =>
                        toggleGraphItem(row.faculty?._id || row.faculty?.id)
                      }
                    />
                  </td>
                  <td className="px-6 py-3 font-medium text-gray-900">
                    {row.faculty?.name || "Unknown"}
                  </td>
                  <td className="px-6 py-3">
                    {Math.floor((row.rate || 0) * 1000) / 10}%
                  </td>
                  <td className="px-6 py-3">{row.courses?.length || 0}</td>
                  <td className="px-6 py-3">{row.sessions || 0}</td>
                  <td className="px-6 py-3">{row.activeAttendees || 0}</td>
                  <td className="px-6 py-3">{row.checkins || 0}</td>
                  <td className="px-6 py-3" />
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Footer Controls */}
      <div className="flex flex-col md:flex-row items-center justify-between p-4 bg-white border-t border-gray-200 gap-4">
        {/* Filters */}
        <div className="flex items-end gap-4 text-sm">
          <span className="text-gray-600 mb-1.5 font-medium">Filter by:</span>
          {/* Min courses */}
          <div className="flex flex-col w-20">
            <span className="text-[10px] text-gray-400 capitalize mb-0.5">
              Min courses
            </span>
            <input
              type="number"
              min="0"
              value={minCourses}
              onChange={(e) => {
                setMinCourses(
                  e.target.value ? parseInt(e.target.value, 10) : "",
                );
                setPage(0);
              }}
              className="border-b border-gray-300 py-1 px-1 focus:outline-none focus:border-blue-500 bg-transparent text-gray-800"
            />
          </div>
          {/* Min sessions */}
          <div className="flex flex-col w-20">
            <span className="text-[10px] text-gray-400 capitalize mb-0.5">
              Min sessions
            </span>
            <input
              type="number"
              min="0"
              value={minSessions}
              onChange={(e) => {
                setMinSessions(
                  e.target.value ? parseInt(e.target.value, 10) : "",
                );
                setPage(0);
              }}
              className="border-b border-gray-300 py-1 px-1 focus:outline-none focus:border-blue-500 bg-transparent text-gray-800"
            />
          </div>
          {/* Min attendees */}
          <div className="flex flex-col w-20">
            <span className="text-[10px] text-gray-400 capitalize mb-0.5">
              Min attendees
            </span>
            <input
              type="number"
              min="0"
              value={minAttendees}
              onChange={(e) => {
                setMinAttendees(
                  e.target.value ? parseInt(e.target.value, 10) : "",
                );
                setPage(0);
              }}
              className="border-b border-gray-300 py-1 px-1 focus:outline-none focus:border-blue-500 bg-transparent text-gray-800"
            />
          </div>
          {/* Min check-ins */}
          <div className="flex flex-col w-24">
            <span className="text-[10px] text-gray-400 capitalize mb-0.5">
              Min check-ins
            </span>
            <input
              type="number"
              min="0"
              value={minCheckins}
              onChange={(e) => {
                setMinCheckins(
                  e.target.value ? parseInt(e.target.value, 10) : "",
                );
                setPage(0);
              }}
              className="border-b border-gray-300 py-1 px-1 focus:outline-none focus:border-blue-500 bg-transparent text-gray-800"
            />
          </div>

          <span className="text-gray-500 text-xs ml-4 mb-2">
            Showing {sortedData.length} out of {fieldData.length}
          </span>
        </div>

        {/* Pagination */}
        <div className="flex items-center gap-6 text-sm text-gray-600">
          <div className="flex items-center gap-2">
            <span>Rows per page:</span>
            <select
              value={rowsPerPage}
              onChange={(e) => {
                setRowsPerPage(Number(e.target.value));
                setPage(0);
              }}
              className="bg-transparent text-gray-700 outline-none cursor-pointer p-1 rounded hover:bg-gray-100"
            >
              <option value={5}>5</option>
              <option value={10}>10</option>
              <option value={25}>25</option>
              <option value={50}>50</option>
              <option value={100}>100</option>
            </select>
          </div>

          <div className="flex items-center gap-4">
            <span>
              {sortedData.length === 0 ? 0 : page * rowsPerPage + 1}-
              {Math.min((page + 1) * rowsPerPage, sortedData.length)} of{" "}
              {sortedData.length}
            </span>
            <div className="flex items-center gap-1">
              <button
                onClick={() => setPage((p) => Math.max(0, p - 1))}
                disabled={page === 0}
                className="p-1 rounded-full hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <ChevronLeft className="w-5 h-5" />
              </button>
              <button
                onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
                disabled={page >= totalPages - 1 || totalPages === 0}
                className="p-1 rounded-full hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

