import { Input } from "@/components/ui/input";
import { Checkbox } from "@/components/ui/checkbox";
import { useAuthStore } from "@/features/auth/store/auth.store";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface GroupMember {
  hostid: string;
  name: string;
  email: string;
  courses: number;
  sessions: number;
}

interface InstituteMembersDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onAddMember: () => void;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function InstituteMembersDialog({
  open,
  onOpenChange,
  onAddMember,
}: InstituteMembersDialogProps) {
  const { t } = useTranslation();
  const user = useAuthStore((s) => s.user);

  const [members, setMembers] = useState<GroupMember[]>([]);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [searchTerm, setSearchTerm] = useState("");

  // Load members from user's group data
  useEffect(() => {
    if (open && user) {
      const u = user as unknown as Record<string, unknown>;
      const gd = (u.data as Record<string, unknown>)?.groupData as
        | { members?: GroupMember[] }
        | undefined;
      if (gd?.members) {
        setMembers(gd.members);
      }
    }
  }, [open, user]);

  // Filter members
  const filtered = useMemo(() => {
    if (!searchTerm) return members;
    const term = searchTerm.toLowerCase();
    return members.filter(
      (m) =>
        m.name.toLowerCase().includes(term) ||
        m.email.toLowerCase().includes(term),
    );
  }, [members, searchTerm]);

  function toggleSelect(hostId: string) {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(hostId)) next.delete(hostId);
      else next.add(hostId);
      return next;
    });
  }

  function toggleSelectAll() {
    if (selectedIds.size === filtered.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filtered.map((m) => m.hostid)));
    }
  }

  async function handleRemoveSelected() {
    if (selectedIds.size === 0) return;
    const confirmed = window.confirm(
      `Remove ${selectedIds.size} member(s) from the group?`,
    );
    if (!confirmed) return;
    // TODO: Call API to remove — for now just remove locally
    setMembers((prev) => prev.filter((m) => !selectedIds.has(m.hostid)));
    setSelectedIds(new Set());
  }

  function handleImpersonate(hostId: string) {
    useAuthStore.getState().setImpersonate(hostId);
    onOpenChange(false);
  }

  function handleAddMember() {
    onAddMember();
    onOpenChange(false);
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[700px] max-h-[80vh]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Users className="h-5 w-5 text-link" />
            {t("institute members - dialog - title") ||
              "Institute Members"}{" "}
            <span className="text-gray-400 font-normal">
              ({members.length})
            </span>
          </DialogTitle>
        </DialogHeader>

        {/* Search + Actions bar */}
        <div className="flex items-center justify-between gap-3 py-2">
          <div className="relative flex-1 max-w-[240px]">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-gray-400" />
            <Input
              placeholder="Search members..."
              value={searchTerm}
              onChange={(e) => startTransition(() => setSearchTerm(e.target.value))}
              className="pl-8 h-8 text-sm"
            />
          </div>

          {selectedIds.size > 0 && (
            <Button
              variant="destructive"
              size="sm"
              onClick={handleRemoveSelected}
              className="h-8"
            >
              <Trash2 className="h-3.5 w-3.5 mr-1" />
              Remove ({selectedIds.size})
            </Button>
          )}
        </div>

        {/* Members table */}
        <div className="overflow-y-auto max-h-[400px] border rounded-md">
          {members.length === 0 ? (
            <div className="text-center py-8 text-gray-400 text-sm">
              <p>No institute members yet.</p>
              <p className="mt-1">
                Click <strong>Add Member</strong> below to invite new members.
              </p>
            </div>
          ) : (
            <table className="w-full text-sm">
              <thead className="bg-gray-50 sticky top-0">
                <tr>
                  <th className="px-3 py-2 text-left w-8">
                    <Checkbox
                      checked={
                        selectedIds.size === filtered.length &&
                        filtered.length > 0
                      }
                      onCheckedChange={toggleSelectAll}
                    />
                  </th>
                  <th className="px-3 py-2 text-left font-medium text-gray-600">
                    Name
                  </th>
                  <th className="px-3 py-2 text-left font-medium text-gray-600">
                    Email
                  </th>
                  <th className="px-3 py-2 text-center font-medium text-gray-600">
                    Courses
                  </th>
                  <th className="px-3 py-2 text-center font-medium text-gray-600">
                    Sessions
                  </th>
                  <th className="px-3 py-2 w-10"></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((member) => (
                  <tr
                    key={member.hostid}
                    className="border-t border-gray-100 hover:bg-gray-50"
                  >
                    <td className="px-3 py-2">
                      <Checkbox
                        checked={selectedIds.has(member.hostid)}
                        onCheckedChange={() => toggleSelect(member.hostid)}
                      />
                    </td>
                    <td className="px-3 py-2 font-medium text-gray-700">
                      {member.name}
                    </td>
                    <td className="px-3 py-2 text-gray-500">{member.email}</td>
                    <td className="px-3 py-2 text-center text-gray-500">
                      {member.courses}
                    </td>
                    <td className="px-3 py-2 text-center text-gray-500">
                      {member.sessions}
                    </td>
                    <td className="px-3 py-2">
                      <button
                        onClick={() => handleImpersonate(member.hostid)}
                        className="text-gray-400 hover:text-link transition-colors"
                        title="View account"
                      >
                        <Eye className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={handleAddMember}>
            <UserPlus className="h-4 w-4 mr-1" />
            {t("institute members - dialog - add member button text") ||
              "Add Member"}
          </Button>
          <Button onClick={() => onOpenChange(false)}>Done</Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from "react";
import { useTranslation } from "react-i18next";
import { CheckCircle2 } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { removeHostInviteToGroup } from "@/shared/services/group.service";
import { useAuthStore } from "@/features/auth/store/auth.store";

interface JoinAdminGroupDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function JoinAdminGroupDialog({
  open,
  onOpenChange,
}: JoinAdminGroupDialogProps) {
  const { t } = useTranslation();
  const user = useAuthStore((s) => s.user);
  const getHostData = useAuthStore((s) => s.getHostData);

  const [submitEnabled, setSubmitEnabled] = useState(false);
  const [invitationAccepted, setInvitationAccepted] = useState(false);

  const groupJoined = (user as Record<string, any>)?.invitationToGroup || {
    groupName: "",
    groupHostName: "",
  };

  const onSubmit = async () => {
    if (!user || !(user as Record<string, any>).invitationToGroup) return;

    setSubmitEnabled(true);
    try {
      await removeHostInviteToGroup(user.id, (user as Record<string, any>).invitationToGroup);
      setInvitationAccepted(true);

      // Refresh user data so the group is updated
      await getHostData();
    } catch (err) {
      console.error("Failed to join group:", err);
    } finally {
      setSubmitEnabled(false);
    }
  };

  const handleOpenChange = (isOpen: boolean) => {
    onOpenChange(isOpen);
    if (!isOpen && invitationAccepted) {
      // Reset after closing
      setTimeout(() => setInvitationAccepted(false), 300);
    }
  };

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent className="sm:max-w-[550px]">
        <DialogHeader>
          <DialogTitle className="text-xl">
            {!invitationAccepted ? (
              t("You have been invited to join an institutional account group!")
            ) : (
              <div className="flex items-center gap-2 text-green-600 dark:text-green-500">
                <CheckCircle2 className="w-6 h-6" />
                <span>{t("Success")}</span>
              </div>
            )}
          </DialogTitle>
        </DialogHeader>

        <div className="py-4 text-slate-700 dark:text-slate-300">
          {!invitationAccepted ? (
            <div className="space-y-4">
              <div>
                <strong>{t("Group name:")}</strong> {groupJoined.groupName}
              </div>
              <div>
                <strong>{t("Group administrator:")}</strong>{" "}
                {groupJoined.groupHostName}
              </div>

              <p className="font-medium mt-4">
                {t(
                  "Joining the group will enable you to use all the premium features that were purchased by your organization.",
                )}
              </p>

              <p className="text-sm bg-blue-50 dark:bg-blue-900/20 text-blue-800 dark:text-blue-300 p-3 rounded-md">
                <strong>{t("Please note:")}</strong>{" "}
                {t(
                  "The account Admin will have access to your attendance reports.",
                )}
              </p>
            </div>
          ) : (
            <div className="text-lg">
              {t("You are now part of")}{" "}
              <strong className="text-primary">{groupJoined.groupName}</strong>{" "}
              {t("group")}
            </div>
          )}
        </div>

        <DialogFooter>
          {!invitationAccepted ? (
            <>
              <Button
                variant="ghost"
                onClick={() => handleOpenChange(false)}
                disabled={submitEnabled}
              >
                {t(
                  "add institute member - dialog - cancel button text",
                  "Cancel",
                )}
              </Button>
              <Button
                onClick={onSubmit}
                disabled={submitEnabled}
                className="min-w-[150px]"
              >
                {submitEnabled ? t("Joining...") : t("Yes - Join group")}
              </Button>
            </>
          ) : (
            <Button
              onClick={() => handleOpenChange(false)}
              className="min-w-[100px]"
            >
              {t("Done")}
            </Button>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useMemo, startTransition } from "react";
import { useTranslation } from "react-i18next";
import {
  Search,
  ChevronLeft,
  ChevronRight,
  ChevronsLeft,
  ChevronsRight,
} from "lucide-react";
import { useAdminStore } from "../../store/admin.store";
import { exportBasicTableToExcel } from "@/shared/utils/export.utils";
import { FileSpreadsheet, MoreVertical, UserPlus } from "lucide-react";

export function AttendeesAdminTable() {
  const { t } = useTranslation();
  const { instituteAttendeesStats, loading } = useAdminStore();
  const [searchTerm, setSearchTerm] = useState("");
  const [page, setPage] = useState(0);
  const rowsPerPage = 25;

  const attendeesData = (instituteAttendeesStats as Record<string, any>)?.classroomData;
  const data = Array.isArray(attendeesData) ? attendeesData : [];

  const filteredData = useMemo(() => {
    if (!searchTerm) return data;
    const lower = searchTerm.toLowerCase();
    return data.filter(
      (a: Record<string, any>) =>
        a?.name?.toLowerCase().includes(lower) ||
        a?.email?.toLowerCase().includes(lower),
    );
  }, [data, searchTerm]);

  // Pagination
  const totalPages = Math.ceil(filteredData.length / rowsPerPage);
  const paginatedData = useMemo(() => {
    const start = page * rowsPerPage;
    return filteredData.slice(start, start + rowsPerPage);
  }, [filteredData, page]);

  const handleExport = () => {
    if (filteredData.length === 0) return;

    // Prepare data
    const exportData = filteredData.map((a: Record<string, any>, idx: number) => [
      idx + 1,
      a?.name || "",
      a?.email || "—",
      a?.courses || 0,
      a?.sessions || 0,
    ]);

    // Header row goes first
    exportData.unshift([
      "#",
      t("Attendee"),
      t("Email"),
      t("Courses"),
      t("Sessions"),
    ]);

    exportBasicTableToExcel({
      fileName: `Attendees_Report_${new Date().toISOString().split("T")[0]}`,
      sheetName: "Attendees",
      data: exportData,
      columnWidths: [10, 30, 40, 15, 15],
    });
  };

  if (loading && data.length === 0) {
    return (
      <div className="bg-white rounded-[4px] shadow-sm border border-gray-100 p-8 flex justify-center w-full">
        <div className="animate-pulse flex flex-col items-center gap-4">
          <div className="h-6 w-48 bg-gray-200 rounded"></div>
          <div className="space-y-3 mt-4">
            <div className="h-4 w-96 bg-gray-200 rounded"></div>
            <div className="h-4 w-96 bg-gray-200 rounded"></div>
            <div className="h-4 w-96 bg-gray-200 rounded"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-[4px] shadow-sm border border-gray-100 overflow-hidden flex flex-col w-full">
      {/* Toolbar */}
      <div className="p-4 border-b border-gray-100 flex items-center justify-end bg-white">
        <div className="flex items-center gap-4">
          <div className="relative w-72">
            <input
              type="text"
              placeholder={t("Search")}
              className="w-full pl-3 pr-9 py-2 text-sm border-b border-gray-300 focus:outline-none focus:border-blue-500 transition-all bg-transparent"
              value={searchTerm}
              onChange={(e) => {
                startTransition(() => setSearchTerm(e.target.value));
                setPage(0);
              }}
            />
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-gray-400" />
          </div>

          {/* Context Menu equivalent to more_vert */}
          <div className="relative group">
            <button className="p-2 text-gray-500 hover:bg-gray-100 rounded-full transition-colors">
              <MoreVertical className="w-5 h-5" />
            </button>
            <div className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-md shadow-lg opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-10">
              <button className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 flex items-center gap-2">
                <UserPlus className="w-4 h-4" />
                {t("Invite a new member")}
              </button>
              <button 
                onClick={handleExport}
                disabled={filteredData.length === 0}
                className="w-full text-left px-4 py-2 text-sm text-gray-700 hover:bg-gray-50 flex items-center gap-2 disabled:opacity-50"
              >
                <FileSpreadsheet className="w-4 h-4" />
                {t("Export")}
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left whitespace-nowrap">
          <thead>
            <tr className="border-b border-gray-200 bg-white text-gray-500 font-medium">
              <th className="px-6 py-3.5 w-16">
                <input type="checkbox" className="rounded text-blue-600 focus:ring-blue-500 cursor-pointer" />
              </th>
              <th className="px-6 py-3.5">{t("Attendee")}</th>
              <th className="px-6 py-3.5">{t("Email")}</th>
              <th className="px-6 py-3.5">{t("Courses")}</th>
              <th className="px-6 py-3.5">{t("Sessions")}</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100 text-gray-700">
            {paginatedData.length === 0 ? (
              <tr>
                <td
                  colSpan={5}
                  className="px-6 py-12 text-center text-gray-500"
                >
                  {t("No attendees found")}
                </td>
              </tr>
            ) : (
              paginatedData.map((attendee: Record<string, any>, idx: number) => (
                <tr
                  key={attendee?.id || idx}
                  className="hover:bg-[#e9e9e9] transition-colors cursor-pointer"
                >
                  <td className="px-6 py-3">
                    <input type="checkbox" className="rounded text-blue-600 focus:ring-blue-500 cursor-pointer" />
                  </td>
                  <td className="px-6 py-3 font-medium text-gray-900">
                    {attendee?.name}
                  </td>
                  <td className="px-6 py-3 text-gray-500">
                    {attendee?.email || "—"}
                  </td>
                  <td className="px-6 py-3">
                    {(attendee?.courses || 0).toLocaleString()}
                  </td>
                  <td className="px-6 py-3">
                    {(attendee?.sessions || 0).toLocaleString()}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination Footer */}
      {totalPages > 1 && (
        <div className="px-6 py-3 flex items-center justify-between border-t border-gray-100 bg-gray-50/50">
          <div className="text-sm text-gray-500">
            {t("Showing")} {page * rowsPerPage + 1} {t("to")}{" "}
            {Math.min((page + 1) * rowsPerPage, filteredData.length)} {t("of")}{" "}
            {filteredData.length}
          </div>
          <div className="flex items-center gap-1">
            <button
              onClick={() => setPage(0)}
              disabled={page === 0}
              className="p-1.5 rounded hover:bg-gray-200 disabled:opacity-50 disabled:cursor-not-allowed text-gray-600"
            >
              <ChevronsLeft className="w-4 h-4" />
            </button>
            <button
              onClick={() => setPage((p) => Math.max(0, p - 1))}
              disabled={page === 0}
              className="p-1.5 rounded hover:bg-gray-200 disabled:opacity-50 disabled:cursor-not-allowed text-gray-600"
            >
              <ChevronLeft className="w-4 h-4" />
            </button>
            <span className="text-sm font-medium px-2 text-gray-600">
              {page + 1} / {totalPages}
            </span>
            <button
              onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
              disabled={page >= totalPages - 1}
              className="p-1.5 rounded hover:bg-gray-200 disabled:opacity-50 disabled:cursor-not-allowed text-gray-600"
            >
              <ChevronRight className="w-4 h-4" />
            </button>
            <button
              onClick={() => setPage(totalPages - 1)}
              disabled={page >= totalPages - 1}
              className="p-1.5 rounded hover:bg-gray-200 disabled:opacity-50 disabled:cursor-not-allowed text-gray-600"
            >
              <ChevronsRight className="w-4 h-4" />
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useMemo, startTransition } from "react";
import { useTranslation } from "react-i18next";
import {
  Search,
  ChevronLeft,
  ChevronRight,
  FileSpreadsheet,
} from "lucide-react";
import { format } from "date-fns";
import { useAdminStore } from "../../store/admin.store";
import { cn } from "@/lib/utils";
import { exportBasicTableToExcel } from "@/shared/utils/export.utils";

export function CoursesAdminTable() {
  const { t } = useTranslation();
  const { coursesStats, loading } = useAdminStore();
  const [sortConfig, setSortConfig] = useState<{
    key: string;
    direction: "asc" | "desc";
  } | null>(null);

  const [searchTerm, setSearchTerm] = useState("");
  const [maxAttendance, setMaxAttendance] = useState<number | "">(100);
  const [minSessions, setMinSessions] = useState<number | "">(1);
  const [minAttendees, setMinAttendees] = useState<number | "">(1);
  const [minCheckins, setMinCheckins] = useState<number | "">(1);

  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(25);

  const data = Array.isArray(coursesStats) ? coursesStats : [];

  const requestSort = (key: string) => {
    let direction: "asc" | "desc" = "asc";
    if (
      sortConfig &&
      sortConfig.key === key &&
      sortConfig.direction === "asc"
    ) {
      direction = "desc";
    }
    setSortConfig({ key, direction });
  };

  const filteredData = useMemo(() => {
    return data.filter((item: any) => {
      if (
        searchTerm &&
        !item.courseName?.toLowerCase().includes(searchTerm.toLowerCase()) &&
        !(Array.isArray(item.hostName) ? item.hostName[0] : item.hostName)?.toLowerCase().includes(searchTerm.toLowerCase())
      )
        return false;
      if (
        maxAttendance !== "" &&
        (item.rate || 0) * 100 > maxAttendance
      )
        return false;
      if (minSessions !== "" && (item.sessions || 0) < minSessions)
        return false;
      if (minAttendees !== "" && (item.activeAttendees || 0) < minAttendees)
        return false;
      if (minCheckins !== "" && (item.checkins || 0) < minCheckins)
        return false;
      return true;
    });
  }, [data, searchTerm, maxAttendance, minSessions, minAttendees, minCheckins]);

  const sortedData = useMemo(() => {
    const sortableItems = [...filteredData];
    if (sortConfig !== null) {
      sortableItems.sort((a: any, b: any) => {
        let aVal = a[sortConfig.key] || 0;
        let bVal = b[sortConfig.key] || 0;

        if (sortConfig.key === "courseName" || sortConfig.key === "hostName") {
          aVal = aVal.toString().toLowerCase();
          bVal = bVal.toString().toLowerCase();
        }

        if (aVal < bVal) return sortConfig.direction === "asc" ? -1 : 1;
        if (aVal > bVal) return sortConfig.direction === "asc" ? 1 : -1;
        return 0;
      });
    }
    return sortableItems;
  }, [filteredData, sortConfig]);

  const paginatedData = useMemo(() => {
    const start = page * rowsPerPage;
    return sortedData.slice(start, start + rowsPerPage);
  }, [sortedData, page, rowsPerPage]);

  const totalPages = Math.ceil(sortedData.length / rowsPerPage);

  const handleExportExcel = async () => {
    if (sortedData.length === 0) return;

    const exportData = sortedData.map((row: any, i: number) => [
      i + 1,
      row.courseName,
      Array.isArray(row.hostName) ? row.hostName[0] : row.hostName,
      `${Math.round((row.rate || 0) * 100)}%`,
      (Array.isArray(row.facultyName) ? row.facultyName[0] : row.facultyName) || "",
      row.sessions || 0,
      row.activeAttendees || 0,
      row.checkins || 0,
    ]);

    exportData.unshift([
      "#",
      t("Course"),
      t("Instructor"),
      t("Attendance"),
      t("Academic unit"),
      t("Sessions"),
      t("Unique Attendees"),
      t("Check-ins"),
    ]);

    exportBasicTableToExcel({
      fileName: `Report_Courses_${format(new Date(), "yyyy-MM-dd")}`,
      sheetName: "Report",
      data: exportData,
      columnWidths: [10, 20, 20, 20, 25, 20, 20, 20],
    });
  };

  if (loading && data.length === 0) {
    return (
      <div className="bg-white rounded-[4px] shadow-sm border border-gray-100 p-8 flex justify-center w-full">
        <div className="animate-pulse flex flex-col items-center gap-4">
          <div className="h-6 w-48 bg-gray-200 rounded"></div>
          <div className="space-y-3 mt-4">
            <div className="h-4 w-96 bg-gray-200 rounded"></div>
            <div className="h-4 w-96 bg-gray-200 rounded"></div>
            <div className="h-4 w-96 bg-gray-200 rounded"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-[4px] shadow-sm border border-gray-100 overflow-hidden flex flex-col w-full">
      <div className="overflow-x-auto">
        <table className="w-full text-sm text-left whitespace-nowrap">
          <thead>
            <tr className="border-b border-gray-300 bg-[#f5f5f5] text-gray-800 font-semibold">
              <th className="px-6 py-4 cursor-pointer hover:bg-gray-100/50 w-16">
                #
              </th>
              <th
