import { useEffect } from "react";
import { useNavigate } from "@tanstack/react-router";
import { useTranslation } from "react-i18next";
import { cn } from "@/lib/utils";
import { useAutoSessionManagement } from "../hooks/useAutoSessionManagement";
import { useAutoModeStore } from "../store/autoModeStore";
import { useAuthStore } from "@/features/auth/store/auth.store";

import { NextSession } from "../components/NextSession";
import { FollowingSessions } from "../components/FollowingSessions";
import { RoomLine } from "../components/RoomLine";
import { AutoModeFooter } from "../components/AutoModeFooter";

export const AutoModePage = () => {
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();
  const isRtl = i18n.language === "he";
  const direction = isRtl ? "rtl" : "ltr";

  const { room, setRoom } = useAutoModeStore();
  const user = useAuthStore((s) => s.user);
  const { nextSession, timeToNextSession, sessions } =
    useAutoSessionManagement();

  // On mount, check if there's a saved room in localStorage
  useEffect(() => {
    const savedRoom = localStorage.getItem("_room_");
    if (savedRoom) {
      try {
        setRoom(JSON.parse(savedRoom));
      } catch (e) {
        setRoom(savedRoom);
      }
    } else if (user?.autoModeRooms?.length) {
      setRoom(user.autoModeRooms[0]);
    }
  }, [setRoom, user]);

  // Enter fullscreen on mount, exit on unmount (matches old app)
  useEffect(() => {
    document.documentElement.requestFullscreen?.().catch(() => {
      // Fullscreen may be blocked by browser policy — silently ignore
    });
    return () => {
      if (document.fullscreenElement) {
        document.exitFullscreen?.().catch(() => {});
      }
    };
  }, []);

  // Handle auto-start when timer reaches 0
  useEffect(() => {
    if (nextSession && timeToNextSession <= 2) {
      handleStartSession();
    }
  }, [timeToNextSession, nextSession]);

  const handleStartSession = () => {
    if (!nextSession) return;
    navigate({ to: "/session/$shortid", params: { shortid: nextSession.id } });
  };

  const handleExitAutoMode = () => {
    // Navigate back to the selected course's info page
    const storedCourseId = localStorage.getItem("_course_id_");
    let courseId: string | null = null;
    if (storedCourseId) {
      try {
        courseId = JSON.parse(storedCourseId);
      } catch {
        courseId = storedCourseId;
      }
    }
    if (courseId) {
      navigate({ to: "/courses/$courseId/sessions", params: { courseId } });
    } else {
      navigate({ to: "/courses" });
    }
  };

  // Theme values from user data (matches old app: user.data?.theme)
  const themeBgColor = user?.theme?.bgColor || "#EFEFEF";
  const themeColor = user?.theme?.color || "#000";
  const themeImage = user?.theme?.image || null;

  // Following sessions: exclude next session, pass with coursename field
  const followingSessions = nextSession
    ? sessions.filter((s) => s.id !== nextSession.id)
    : [];

  return (
    <div
      className={cn(
        "h-full flex flex-col items-center justify-start",
        isRtl ? "font-[Heebo,sans-serif]" : "font-[Muli,sans-serif]",
      )}
      style={{ direction }}
    >
      {/* Header — Theme Logo Bar */}
      <div
        className="w-full flex justify-start items-center"
        style={{ background: themeBgColor, color: themeColor }}
      >
        {themeImage && (
          <div className="m-[10px] h-[80px]">
            <img src={themeImage} alt="logo" className="h-full" />
          </div>
        )}
      </div>

      {/* Info Container */}
      <div className="flex flex-col items-center justify-center mb-[10px] h-[80%] w-full relative">
        {/* Sessions Info Container */}
        <div className="flex flex-row items-stretch justify-around w-full relative">
          {/* Room Selector (positioned above) */}
          <RoomLine
            room={room}
            rooms={user?.autoModeRooms || []}
            onChangeRoom={setRoom}
          />

          {/* Waiting state */}
          {(!nextSession || timeToNextSession >= 1_000_000_000) && (
            <div className="text-[30px]">
              {`${t("Waiting for sessions")}...`}
            </div>
          )}

          {/* Sessions content */}
          {nextSession && timeToNextSession < 1_000_000_000 && (
            <div className="flex flex-row items-stretch justify-around w-full relative">
              <div className="flex-1 flex flex-col items-center">
                <NextSession
                  nextSession={nextSession}
                  timeToNextSession={timeToNextSession}
                  onStartNow={handleStartSession}
                  direction={direction}
                />
              </div>
              <div className="flex-1 flex flex-col items-center">
                <FollowingSessions
                  sessions={followingSessions}
                  direction={direction}
                />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Footer */}
      <AutoModeFooter
        onExitAutoMode={handleExitAutoMode}
        isRtl={isRtl}
      />
    </div>
  );
};

import { useState } from "react";
import { useTranslation } from "react-i18next";
import { Gift } from "lucide-react";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { getDiscountCodeInfo } from "@/shared/services/host.service";
import { useAuthStore } from "@/features/auth/store/auth.store";

interface DiscountCodeDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onApplyCode?: (code: string) => void;
}

export function DiscountCodeDialog({
  open,
  onOpenChange,
  onApplyCode,
}: DiscountCodeDialogProps) {
  const { t } = useTranslation();
  const updateUserData = useAuthStore((s) => s.updateUserData);

  const [discountCode, setDiscountCode] = useState("");
  const [codeError, setCodeError] = useState(false);
  const [errorText, setErrorText] = useState("");
  const [loadingCode, setLoadingCode] = useState(false);
  const [codeData, setCodeData] = useState<any>(null);
  const [codeSuccessfullyLoaded, setCodeSuccessfullyLoaded] = useState(false);

  const handleOpenChange = (isOpen: boolean) => {
    if (!isOpen) {
      // Reset state on close
      setTimeout(() => {
        setDiscountCode("");
        setCodeError(false);
        setErrorText("");
        setCodeSuccessfullyLoaded(false);
        setCodeData(null);
      }, 300);
    }
    onOpenChange(isOpen);
  };

  const checkDiscountCode = async () => {
    if (discountCode.length < 4) {
      setCodeError(true);
      setErrorText(t("Invalid code"));
      return;
    }

    setLoadingCode(true);
    try {
      const data: any = await getDiscountCodeInfo(discountCode);
      if (!data) {
        setCodeError(true);
        setErrorText(t("Invalid code"));
      } else {
        const code = data.result;
        const now = new Date();
        const codeValidityDate = new Date(code.validUntil);

        if (isNaN(codeValidityDate.getTime())) {
          setCodeError(true);
          setErrorText(t("Invalid code expiration"));
        } else if (now > codeValidityDate) {
          setCodeError(true);
          setErrorText(t("Code is expired"));
        } else {
          setCodeError(false);
          setCodeData(code);
          setCodeSuccessfullyLoaded(true);
        }
      }
    } catch (e) {
      setCodeError(true);
      setErrorText(t("Invalid code"));
      console.error("Error in get discount code: ", e);
    } finally {
      setLoadingCode(false);
    }
  };

  const handleSuccessClick = async () => {
    if (onApplyCode) {
      onApplyCode(discountCode);
    }
    try {
      await updateUserData({ discountCode } as any);
    } catch (err) {
      console.error(err);
    }
    handleOpenChange(false);
  };

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent className="sm:max-w-[450px] p-6">
        <div className="flex flex-col items-center justify-center text-center space-y-6">
          <div className="flex items-center gap-2 text-2xl font-semibold text-primary">
            <Gift className="w-8 h-8 text-primary" />
            <span>{t("Discount Code")}</span>
          </div>

          {!codeSuccessfullyLoaded ? (
            <div className="w-full space-y-4">
              <p className="text-slate-600 dark:text-slate-300">
                {t("Got a discount code? Enter it here:")}
              </p>

              <div className="space-y-2">
                <Input
                  value={discountCode}
                  onChange={(e) => {
                    setDiscountCode(e.target.value.toUpperCase());
                    setCodeError(false);
                    setErrorText("");
                  }}
                  placeholder={t("Enter code")}
                  className={`text-center uppercase text-lg tracking-widest ${
                    codeError ? "border-red-500 focus-visible:ring-red-500" : ""
                  }`}
                  maxLength={20}
                />
                {codeError && (
                  <p className="text-sm text-red-500">{errorText}</p>
                )}
              </div>

              <div className="pt-4 flex justify-center">
                <Button
                  onClick={checkDiscountCode}
                  disabled={loadingCode || !discountCode}
                  className="w-full sm:w-auto min-w-[150px]"
                >
                  {loadingCode ? t("Verifying...") : t("Apply Code")}
                </Button>
              </div>
            </div>
          ) : (
            <div className="w-full space-y-6">
              <div className="py-4 px-6 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-lg text-green-700 dark:text-green-400 font-medium">
                {codeData?.discount}% {t("discount applied successfully!")}
              </div>

              <Button
                onClick={handleSuccessClick}
                className="w-full sm:w-auto min-w-[150px]"
              >
                {t("OK")}
              </Button>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

/**
