          >
            <span>
              By the{" "}
              <a href="https://ezcheck.me" style={{ color: "#1976d2" }}>
                EZCheck.me
              </a>{" "}
              team
            </span>
            <span>{formattedDate}</span>
          </div>

          {/* Content */}
          <div
            className="blog-content"
            style={{ margin: "10px 60px" }}
            dangerouslySetInnerHTML={{
              __html: DOMPurify.sanitize(post.content),
            }}
          />

          {/* Read Next */}
          {nextPost && (
            <div className="flex flex-row mb-10 mt-8">
              <h6
                style={{
                  fontSize: 17,
                  margin: "0 60px",
                  fontWeight: 500,
                }}
              >
                Read Next:{" "}
                <Link
                  to="/blog/$id"
                  params={{ id: nextPost.slug || nextPost.id }}
                  style={{ color: "#1976d2" }}
                >
                  {nextPost.title}
                </Link>
              </h6>
            </div>
          )}
        </div>
      </div>

      {/* Blog content styles — match old app's WordPress content rendering */}
      <style>{`
        .blog-content p {
          margin-block-end: 0;
          margin-block-start: 0.5rem;
        }
        .blog-content img {
          width: 100%;
        }
        .blog-content a {
          color: #1976d2;
          text-decoration: underline;
        }
        @media (max-width: 700px) {
          .blog-content {
            font-size: 16px;
            margin: 10px 20px !important;
          }
        }
      `}</style>
    </div>
  );
}

