                    placeholder="Last Name*"
                    required
                    autoComplete="off"
                    style={inputStyle}
                  />
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="Email address*"
                    required
                    autoComplete="off"
                    style={inputStyle}
                  />
                  <input
                    type="tel"
                    pattern="[0-9]*"
