                className="flex items-center justify-center w-full py-1 font-medium"
                style={{ color: "#4caf50" }}
              >
                {t("homepage - checking-in - sms sent")}
              </div>
            )}
          </div>

          {/* Error message */}
          {error && (
            <p className="text-red-500 text-sm text-center mt-2">{error}</p>
