/**
 * Course QR Code Download Dialog — generates a printable QR sign PDF.
 * Replaces old CourseQrCodeDownloadDialog.js (115 lines) + QrPdf.js.
 * Uses qr-logo for QR generation and @react-pdf/renderer for PDF output.
 */

import { useEffect, useState } from "react";
import { useTranslation } from "react-i18next";
import { Loader2, QrCode as QrCodeIcon, Download } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { useAuthStore } from "@/features/auth/store/auth.store";

// Import QRLogo from the qr-logo package
// eslint-disable-next-line @typescript-eslint/no-require-imports
import QRLogo from "qr-logo";

// PDF components
import {
  Document,
  Page,
  Text,
  View,
  Image,
  StyleSheet,
  PDFDownloadLink,
} from "@react-pdf/renderer";

interface CourseQrCodeDownloadDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  course: {
    id: string;
    _id?: string;
    name: string;
  };
}

// ---------------------------------------------------------------------------
// PDF Document
// ---------------------------------------------------------------------------

const pdfStyles = StyleSheet.create({
  page: {
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    padding: 40,
  },
  logoContainer: {
    width: 120,
    height: 120,
    borderRadius: 12,
    justifyContent: "center",
    alignItems: "center",
    marginBottom: 20,
  },
  logo: {
    width: 80,
    height: 80,
    objectFit: "contain",
  },
  courseName: {
    fontSize: 28,
    fontWeight: "bold",
    marginBottom: 20,
    textAlign: "center",
    maxWidth: 400,
  },
  qrImage: {
    width: 300,
    height: 300,
    marginBottom: 20,
  },
  scanText: {
    fontSize: 18,
    color: "#555",
    textAlign: "center",
  },
});

function QrPdfDocument({
  course,
  qrImage,
  theme,
  t,
}: {
  course: { name: string };
  qrImage: string;
  theme?: { bgColor?: string; image?: string };
  t: (key: string) => string;
}) {
  return (
    <Document>
      <Page size="A4" style={pdfStyles.page}>
        {theme?.image && (
          <View
            style={[
              pdfStyles.logoContainer,
              { backgroundColor: theme.bgColor || "#0277bd" },
            ]}
          >
            <Image src={theme.image} style={pdfStyles.logo} />
          </View>
        )}
        <Text style={pdfStyles.courseName}>{course.name}</Text>
        <Image src={qrImage} style={pdfStyles.qrImage} />
        <Text style={pdfStyles.scanText}>
          {t("Scan the Code to Self Check-in")}
        </Text>
      </Page>
    </Document>
  );
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function generateRandomString(): string {
  const chars =
    "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
  let result = "";
  for (let i = 0; i < 2; i++) {
    result += chars[Math.floor(Math.random() * chars.length)];
  }
  return result;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function CourseQrCodeDownloadDialog({
  open,
  onOpenChange,
  course,
}: CourseQrCodeDownloadDialogProps) {
  const { t } = useTranslation();
  const user = useAuthStore((s) => s.user);
  const [qrImage, setQrImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const theme = (user as any)?.data?.theme;
  const courseId = course._id || course.id;

  useEffect(() => {
    if (!open) return;

    setLoading(true);
    setQrImage(null);

    const r = generateRandomString;
    const url = `https://ezcheck.me/${r()}${r()}${r()}/${r()}${courseId}${r()}/self`;

    const qrLogo = new QRLogo("assets/images/logos/printable_session_logo.png");

    qrLogo
      .generate(url, { errorCorrectionLevel: "H", margin: 0, width: 1200 }, 3.3)
      .then((image: string) => {
        setQrImage(image);
        setLoading(false);
      })
      .catch((err: any) => {
        console.error("QR generation failed:", err);
        setLoading(false);
      });
  }, [open, courseId]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[480px]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <QrCodeIcon className="w-5 h-5" />
            Download Printable Course Sign
          </DialogTitle>
        </DialogHeader>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-gray-400 mb-4" />
            <p className="text-sm text-gray-500">Generating QR code...</p>
          </div>
        ) : qrImage ? (
          <div className="flex flex-col items-center py-4 space-y-4">
            {/* Preview */}
            <div className="border rounded-lg p-6 bg-white shadow-sm flex flex-col items-center space-y-3">
              {theme?.image && (
                <div
                  className="w-16 h-16 rounded-lg flex items-center justify-center"
                  style={{ backgroundColor: theme.bgColor || "#0277bd" }}
                >
                  <img
                    src={theme.image}
                    alt=""
                    className="w-10 h-10 object-contain"
                  />
                </div>
              )}
              <p className="font-bold text-lg text-center">{course.name}</p>
              <img
                src={qrImage}
                alt="QR Code"
                className="w-48 h-48 object-contain"
              />
              <p className="text-sm text-gray-500">
                {t("Scan the Code to Self Check-in")}
              </p>
            </div>

            {/* Instructions */}
            <div className="text-xs text-gray-500 text-center space-y-1 px-4">
              <p>
                Download and print this sign and hang it at the self-check-in
                location to help attendees to check-in easily.
              </p>
              <p>
                Note: This is optional. Attendees listed in the course can
                self-check-in without scanning the QR.
              </p>
            </div>

            {/* Download PDF */}
            <PDFDownloadLink
              document={
                <QrPdfDocument
                  course={course}
                  qrImage={qrImage}
                  theme={theme}
                  t={t}
                />
              }
              fileName={`${course.name} QR check-in sign.pdf`}
              className="inline-flex items-center gap-2 bg-link hover:bg-link/90 text-white px-6 py-2.5 rounded-md text-sm font-medium transition-colors"
            >
              {({ loading: pdfLoading }) =>
                pdfLoading ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Preparing PDF...
                  </>
                ) : (
                  <>
                    <Download className="w-4 h-4" />
                    Download the Sign
                  </>
                )
              }
            </PDFDownloadLink>
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-12 text-gray-500">
            <p>Failed to generate QR code. Please try again.</p>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

/**
 * Course Sessions tab view — exact parity with production app.
 * Table with columns: checkbox, #, Session, Label, Session ID, Date & Time,
 * Check-ins, Attendance Rate.
 *
 * Toolbar ⋮ menu: Create Future Sessions, Delete Sessions, Rename session,
 * Edit Session time, Merge Sessions (matches old app exactly).
 *
 * Source: CourseSessions.js (272 lines) + courses.style.js
 */

import { useState, useEffect, useMemo, startTransition } from "react";
import { useNavigate } from "@tanstack/react-router";
import {
  Search,
  ChevronRight,
  ChevronLeft,
  MoreVertical,
  Calendar,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useCourseStore } from "../store/course.store";
import { useSessionStore } from "../store/session.store";

import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { RenameSessionDialog } from "@/features/sessions/components/RenameSessionDialog";
import { EditSessionDateTimeDialog } from "@/features/sessions/components/EditSessionDateTimeDialog";
import { CreateFutureSessionsDialog } from "./CreateFutureSessionsDialog";
import { MergeSessionsDialog } from "./MergeSessionsDialog";
import { ImportSessionsFromExcelDialog } from "./ImportSessionsFromExcelDialog";
import { ConfirmationDialog } from "@/shared/components/ConfirmationDialog";
import { StartSessionDialog } from "@/features/sessions/components/StartSessionDialog";
import type { Session } from "@/shared/types/session.types";
import { Skeleton } from "@/components/ui/skeleton";
import {
  SESSION_TYPE_LIST,
  getSessionLabelType,
} from "@/config/sessionLabelTypes";

export function CourseSessions() {
  const courseId = useCourseStore((s) => s.courseId);
  const courses = useCourseStore((s) => s.courses);

  const sessions = useSessionStore((s) => s.sessions);
  const loading = useSessionStore((s) => s.loading);
  const getCourseSessions = useSessionStore((s) => s.getCourseSessions);
  const updateSession = useSessionStore((s) => s.updateSession);

  // Get the current course (same as legacy mapStateToProps)
  const course = courses?.find((c) => c.id === courseId) ?? null;

  const navigate = useNavigate();

  // --- Search state ---
  const [searchQuery, setSearchQuery] = useState("");

  // --- Pagination state ---
  const [page, setPage] = useState(0);
  const PAGE_SIZES = [25, 50, 100];
  const [pageSize, setPageSize] = useState(25);

  // --- Checkbox selection ---
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // --- Hover state for row actions ---
  const [hoveredSessionId, setHoveredSessionId] = useState<string | null>(null);

  // --- Dialog states ---
  const [sessionToRename, setSessionToRename] = useState<Session | null>(null);
  const [sessionToEditDate, setSessionToEditDate] = useState<Session | null>(
    null,
  );
  const [sessionToResume, setSessionToResume] = useState<Session | null>(null);
  const [showCreateFuture, setShowCreateFuture] = useState(false);
  const [showMergeSessions, setShowMergeSessions] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [showImportSessions, setShowImportSessions] = useState(false);
  const [deleteLoading, setDeleteLoading] = useState(false);

  useEffect(() => {
    if (courseId) {
      getCourseSessions(courseId);
    }
  }, [courseId, getCourseSessions]);

  // Reset selection when sessions change
  useEffect(() => {
    setSelectedIds(new Set());
  }, [sessions]);

  // --- Filtered sessions ---
  const filteredSessions = useMemo(() => {
    if (!searchQuery.trim()) return sessions;
    const q = searchQuery.toLowerCase();
    return sessions.filter(
      (s) =>
        (s.name || "").toLowerCase().includes(q) ||
        // Cast id to String to avoid crash when API returns a numeric id
        String(s.shortId ?? s.id ?? "").toLowerCase().includes(q) ||
        (s.label || "").toLowerCase().includes(q),
    );
  }, [sessions, searchQuery]);

  // --- Paged sessions ---
  const pagedSessions = useMemo(() => {
    const start = page * pageSize;
    return filteredSessions.slice(start, start + pageSize);
  }, [filteredSessions, page, pageSize]);

  const totalPages = Math.max(1, Math.ceil(filteredSessions.length / pageSize));

  // Reset to page 0 when filter or page size changes
  useEffect(() => {
    setPage(0);
  }, [searchQuery, pageSize]);

  // --- Checkbox helpers ---
  const allSelected =
    filteredSessions.length > 0 &&
    filteredSessions.every((s) => selectedIds.has(s.id));
  const someSelected =
    filteredSessions.some((s) => selectedIds.has(s.id)) && !allSelected;

  const toggleSelectAll = () => {
    if (allSelected) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filteredSessions.map((s) => s.id)));
    }
  };

  const toggleOne = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  };

  // --- Handlers ---
  const handleSessionClick = (sessionId: string) => {
    if (courseId) {
      useCourseStore.getState().setStudentId(null);
      useSessionStore.getState().selectSession(courseId, sessionId);
      navigate({
        to: "/courses/$courseId/session/$sessionId",
        params: { courseId, sessionId },
      });
    }
  };

  async function handleDeleteSessions() {
    if (!courseId || selectedIds.size === 0) return;
    setDeleteLoading(true);
    try {
      const deleteSession = useSessionStore.getState().deleteSession;
      for (const id of selectedIds) {
        await deleteSession(courseId, id);
      }
      setSelectedIds(new Set());
      setShowDeleteConfirm(false);
      // Refresh sessions
      getCourseSessions(courseId);
    } catch (err) {
      console.error("Failed to delete sessions:", err);
    } finally {
      setDeleteLoading(false);
    }
  }

  async function handleCreateFutureSessions(_dates: Date[]) {
    // The CreateFutureSessionsDialog calls onCreateSessions with dates.
    if (courseId) {
      getCourseSessions(courseId);
    }
  }

  async function handleMergeSessions(
    _targetSessionId: string,
    _sessionIds: string[],
    _mergeCourseId: string,
    _method: "AND" | "OR",
  ) {
    // TODO: Call merge sessions API
    if (courseId) {
      getCourseSessions(courseId);
    }
  }

  // Helper: get the first selected session for rename/edit
  function getFirstSelected(): Session | null {
    for (const s of sessions) {
      if (selectedIds.has(s.id)) return s;
    }
    return null;
  }

  // Helper: get all selected sessions for merge dialog
  function getSelectedSessions() {
    return sessions
      .filter((s) => selectedIds.has(s.id))
      .map((s) => ({
        _id: s.id,
        name: s.name || `Session ${s.serialId ?? ""}`,
        shortid: s.shortId || s.id,
        begins: s.begins ?? 0,
        attendees: [],
        courseid: courseId || "",
      }));
  }

  // --- Render ---

  if (loading) {
    return (
      <div className="flex flex-col h-full bg-white">
        {/* Skeleton toolbar */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200">
          <Skeleton width={140} height={20} borderRadius={3} />
          <Skeleton width={180} height={24} borderRadius={3} />
        </div>
        {/* Skeleton rows */}
        <div className="px-4 py-2 space-y-3">
          {Array.from({ length: 6 }).map((_, i) => (
            <div key={i} className="flex items-center gap-4" style={{ height: 48 }}>
              <Skeleton width={16} height={16} borderRadius={3} />
              <Skeleton width={24} height={12} borderRadius={3} />
              <Skeleton width={`${18 + (i % 3) * 5}%`} height={12} borderRadius={3} />
              <Skeleton width={64} height={12} borderRadius={3} />
              <Skeleton width={72} height={12} borderRadius={3} />
              <Skeleton width={100} height={12} borderRadius={3} />
              <Skeleton width={48} height={12} borderRadius={3} />
              <Skeleton width={40} height={12} borderRadius={3} />
            </div>
          ))}
        </div>
      </div>
    );
  }

  if (sessions.length === 0) {
    return (
      <div className="flex flex-col items-center gap-2 py-16 text-center">
        <Calendar className="h-8 w-8 text-gray-300" />
        <p className="text-sm text-gray-500">No sessions yet</p>
        <p className="text-xs text-gray-400">
          Start a session to begin tracking attendance
        </p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white">
      {/* Table Header / Toolbar */}
      <div className="flex items-center justify-between px-5 py-4">
        <div className="flex items-center gap-2">
          <h2 className="text-[20px] font-semibold text-[#222]">
            Sessions ({filteredSessions.length})
          </h2>

          {/* Toolbar ⋮ menu — matches old app exactly */}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <button className="p-1 rounded-full hover:bg-gray-100 text-gray-500">
                <MoreVertical className="h-5 w-5" />
              </button>
            </DropdownMenuTrigger>
            <DropdownMenuContent side="right" align="start">
              <DropdownMenuItem onClick={() => setShowCreateFuture(true)}>
                Create Future Sessions...
              </DropdownMenuItem>
              <DropdownMenuItem
                disabled={selectedIds.size === 0}
                onClick={() => setShowDeleteConfirm(true)}
              >
                Delete Sessions...
              </DropdownMenuItem>
              <DropdownMenuItem
                disabled={selectedIds.size === 0}
                onClick={() => setSessionToRename(getFirstSelected())}
              >
                Rename session...
              </DropdownMenuItem>
              <DropdownMenuItem
                disabled={selectedIds.size === 0}
                onClick={() => setSessionToEditDate(getFirstSelected())}
              >
                Edit Session time...
              </DropdownMenuItem>
              <DropdownMenuItem
                disabled={selectedIds.size < 2}
                onClick={() => setShowMergeSessions(true)}
              >
                Merge Sessions...
              </DropdownMenuItem>
              <DropdownMenuItem
                onClick={() => setShowImportSessions(true)}
              >
                Import Sessions from file...
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>

        {/* Search */}
        <div className="relative">
          <input
            type="text"
            placeholder="Search"
            value={searchQuery}
            onChange={(e) => startTransition(() => setSearchQuery(e.target.value))}
            className="w-64 border-b border-gray-300 pb-1 text-sm focus:outline-none focus:border-blue-500 transition-colors"
          />
          <Search className="absolute right-0 bottom-2 h-4 w-4 text-gray-600" />
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-gray-200">
              <th className="px-4 py-3 text-left w-12">
                <input
                  type="checkbox"
                  className="rounded border-gray-300"
                  checked={allSelected}
                  ref={(el) => {
                    if (el) el.indeterminate = someSelected;
                  }}
                  onChange={toggleSelectAll}
                />
              </th>
              <th className="px-2 py-3 text-left font-normal text-gray-600 w-12">
                #
              </th>
              <th className="px-4 py-3 text-left font-normal text-gray-600">
                Session
              </th>
              <th className="px-4 py-3 text-left font-normal text-gray-600">
                Label
              </th>
              <th className="px-4 py-3 text-left font-normal text-gray-600">
                Session ID
              </th>
              <th className="px-4 py-3 text-left font-normal text-gray-600">
                Date & Time
              </th>
              <th className="px-4 py-3 text-left font-normal text-gray-600">
                Check-ins
              </th>
              <th className="px-4 py-3 text-left font-normal text-gray-600">
                Attendance Rate
              </th>
              {/* Empty column for Resume session link — fixed width, always present */}
              <th style={{ width: 160 }} />
            </tr>
          </thead>
          <tbody>
            {pagedSessions.map((session) => {
              const globalIdx = filteredSessions.indexOf(session);
              // Legacy formula: Math.round(session.checkins / course.maxattendance * 100)
              const checkinCount = session.checkins ?? 0;
              const maxAttendance = course?.maxattendance ?? 0;
              const rate = maxAttendance > 0
                  ? Math.round((checkinCount / maxAttendance) * 100)
                  : 0;

              // Resolve the label type from constants (matches old app DropDownMenu behavior)
              const labelType = getSessionLabelType(session.label);

              const isChecked = selectedIds.has(session.id);

              return (
                <tr
                  key={session.id}
                  onClick={() => handleSessionClick(session.id)}
                  onMouseEnter={() => setHoveredSessionId(session.id)}
                  onMouseLeave={() => setHoveredSessionId(null)}
                  className="cursor-pointer hover:bg-gray-50 transition-colors border-b border-gray-100"
                  style={{ height: 48 }}
                >
                  <td
                    className="px-4 text-center"
                    onClick={(e) => e.stopPropagation()}
                    onMouseDown={(e) => e.stopPropagation()}
                  >
                    <input
                      type="checkbox"
                      className="rounded border-gray-300 cursor-pointer"
                      checked={isChecked}
                      onChange={() => toggleOne(session.id)}
                      tabIndex={-1}
                    />
                  </td>
                  <td className="px-2 text-gray-600">
                    {filteredSessions.length - globalIdx}
                  </td>
                  <td className="px-4 text-[rgba(0,0,0,0.87)]">
                    {session.name || `Session ${session.serialId ?? ""}`}
                  </td>
                  {/* Label dropdown — matches old app's DropDownMenu in CourseSessionRow.js */}
                  <td
                    className="px-4"
                    onClick={(e) => e.stopPropagation()}
                  >
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <button
                          className={cn(
                            "text-left text-sm bg-transparent border-none outline-none cursor-pointer hover:underline",
                          )}
                          style={{ color: labelType.color }}
                        >
                          {labelType.label}
                        </button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="start" className="min-w-[180px]">
                        {SESSION_TYPE_LIST.map((type) => (
                          <DropdownMenuItem
                            key={type.id}
                            onClick={async () => {
                              if (courseId) {
                                await updateSession(courseId, session.id, {
                                  name: session.name,
                                  label: type.id,
                                  action: "update",
                                });
                              }
                            }}
                            style={{ color: type.color }}
                          >
                            {type.label}
                          </DropdownMenuItem>
                        ))}
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </td>
                  <td className="px-4 text-[rgba(0,0,0,0.87)]">{session.shortId || session.id}</td>
                  <td className="px-4 text-[rgba(0,0,0,0.87)]">
                    {session.begins
                      ? new Date(session.begins)
                          .toLocaleString("en-US", {
                            month: "short",
                            day: "numeric",
                            year: "numeric",
                            hour: "2-digit",
                            minute: "2-digit",
                            hour12: false,
                          })
                          .replace(/,/g, "")
                      : "—"}
                  </td>
                  <td className="px-4 text-[rgba(0,0,0,0.87)]">{checkinCount}</td>
                  <td className="px-4 text-[rgba(0,0,0,0.87)]">
                    {rate}%
                  </td>
                  {/* Resume session link — own column, visibility-based */}
                  <td style={{ width: 160, padding: '0 8px' }}>
                    <button
                      className="text-sm text-gray-500 hover:text-gray-700 inline-flex items-center gap-1 whitespace-nowrap transition-opacity"
                      style={{
                        opacity: hoveredSessionId === session.id ? 1 : 0,
                        pointerEvents: hoveredSessionId === session.id ? 'auto' : 'none',
                      }}
                      onClick={(e) => {
                        e.stopPropagation();
                        setSessionToResume(session);
                      }}
                    >
                      ▶ Resume session...
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Dialogs */}
      <StartSessionDialog
        open={!!sessionToResume}
        onOpenChange={(open) => !open && setSessionToResume(null)}
        resumedSession={sessionToResume}
        onSessionStarted={(session) => {
          setSessionToResume(null);
          try {
            document.documentElement.requestFullscreen?.().catch(() => {});
          } catch { /* fullscreen not available */ }
          navigate({
            to: "/session/$shortid",
            params: { shortid: session.shortId || session.shortid || session.id },
          });
        }}
      />
      <RenameSessionDialog
        open={!!sessionToRename}
        onOpenChange={(open) => !open && setSessionToRename(null)}
        session={sessionToRename}
        courseId={courseId || ""}
      />
      <EditSessionDateTimeDialog
        open={!!sessionToEditDate}
        onOpenChange={(open) => !open && setSessionToEditDate(null)}
        session={sessionToEditDate}
        courseId={courseId || ""}
      />
      <CreateFutureSessionsDialog
        open={showCreateFuture}
        onOpenChange={setShowCreateFuture}
        onCreateSessions={handleCreateFutureSessions}
      />
      <MergeSessionsDialog
        open={showMergeSessions}
        onOpenChange={setShowMergeSessions}
        selectedSessions={getSelectedSessions()}
        onMerge={handleMergeSessions}
      />
      <ImportSessionsFromExcelDialog
        open={showImportSessions}
        onOpenChange={setShowImportSessions}
        courseName={course?.name || ""}
        onImport={async (sessions) => {
          // TODO: implement session import API call
          void sessions;
        }}
      />
      <ConfirmationDialog
        open={showDeleteConfirm}
        onOpenChange={setShowDeleteConfirm}
        title="Delete Sessions"
        description={`Are you sure you want to delete ${selectedIds.size} selected session(s)? This action cannot be undone.`}
        confirmLabel="Delete"
        destructive
        loading={deleteLoading}
        onConfirm={handleDeleteSessions}
      />

      {/* Pagination Footer */}
      <div className="flex items-center justify-end px-6 py-4 text-sm text-gray-600 border-t border-gray-200 mt-auto">
        <div className="flex items-center gap-2 mr-8">
          <span>Rows per Page</span>
          <select
            className="bg-transparent focus:outline-none"
            value={pageSize}
            onChange={(e) => setPageSize(Number(e.target.value))}
          >
            {PAGE_SIZES.map((s) => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </div>
        <div className="flex items-center gap-4">
          <span>
            {filteredSessions.length === 0
              ? "0"
              : `${page * pageSize + 1}-${Math.min((page + 1) * pageSize, filteredSessions.length)} of ${filteredSessions.length}`
            }
          </span>
          <div className="flex gap-2">
            <button
              className={cn(
                "p-1 transition-colors",
                page === 0
                  ? "text-gray-300 cursor-not-allowed"
                  : "text-gray-500 hover:text-gray-700 cursor-pointer",
              )}
              disabled={page === 0}
              onClick={() => setPage((p) => Math.max(0, p - 1))}
            >
              <ChevronLeft className="h-5 w-5" />
            </button>
            <button
              className={cn(
                "p-1 transition-colors",
                page >= totalPages - 1
                  ? "text-gray-300 cursor-not-allowed"
                  : "text-gray-500 hover:text-gray-700 cursor-pointer",
              )}
              disabled={page >= totalPages - 1}
              onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
            >
              <ChevronRight className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Course Students tab view — matches legacy CourseStudents.js.
 * Table with columns: Checkbox | Last Name (avatar) | First Name | Attendance Rate | 1..N session ✓/✗
 *
 * Legacy key behaviors:
 * - Sessions reversed to show oldest→newest as columns 1..N
 * - Each session column header is the index (1, 2, 3...)
 * - Tooltip on session column header shows session name + date
 * - Green/red circle icons for each student×session cell
 * - Attendance rate = sessions attended / total sessions × 100
 * - "Attendees (N)" header with three-dot menu
 * - Pagination footer with "Rows per Page 25" + "N-M of T"
 */

import { useEffect, useState, useMemo, startTransition } from "react";
import { Search, Users, MoreVertical } from "lucide-react";
import { useCourseStore } from "../store/course.store";
import { useStudentStore } from "../store/student.store";
import { useSessionStore } from "../store/session.store";
import { COURSE_VIEWS, CHECKIN_METHODS, type CourseView } from "@/config/constants";
import { CourseStudentsMenu } from "./CourseStudentsMenu";
import { AddStudentDialog } from "./AddStudentDialog";
import { DeleteStudentsDialog } from "./DeleteStudentsDialog";
import { ManualCheckInDialog } from "./ManualCheckInDialog";
import { Skeleton } from "@/components/ui/skeleton";
import { useAuthStore } from "@/features/auth/store/auth.store";
import type { Student } from "@/shared/types";

export function CourseStudents() {
  const courseId = useCourseStore((s) => s.courseId);
  const viewCourse = useCourseStore((s) => s.viewCourse);
  const students = useStudentStore((s) => s.students);
  const loading = useStudentStore((s) => s.loading);
  const getCourseStudents = useStudentStore((s) => s.getCourseStudents);
  const sessions = useSessionStore((s) => s.sessions);
  const getCourseSessions = useSessionStore((s) => s.getCourseSessions);
  const checkUncheck = useSessionStore((s) => s.checkUncheck);
  const user = useAuthStore((s) => s.user);
  const isPremium = user?.plan === "Premium";

  const [searchTerm, setSearchTerm] = useState("");
  const [selected, setSelected] = useState<string[]>([]);
  const [addStudentOpen, setAddStudentOpen] = useState(false);
  const [deleteStudentsOpen, setDeleteStudentsOpen] = useState(false);
  const [rowsPerPage, setRowsPerPage] = useState(25);
  const [page, setPage] = useState(0);
  const [checkinTarget, setCheckinTarget] = useState<{
    student: Student;
    sessionId: string;
    sessionName: string;
    studentSession: any;
  } | null>(null);

  useEffect(() => {
    if (courseId) {
      getCourseStudents(courseId);
      // Also ensure sessions are loaded (needed for per-session columns)
      if (sessions.length === 0) {
        getCourseSessions(courseId);
      }
    }
  }, [courseId, getCourseStudents, getCourseSessions]);

  // Sessions reversed (oldest first) for column display, matching legacy
  const sessionsCopy = useMemo(
    () => sessions.slice().reverse(),
    [sessions],
  );

  const filteredStudents = useMemo(() => {
    const list = !searchTerm
      ? students
      : students.filter((s) => {
          const term = searchTerm.toLowerCase();
          return (
            s.name?.toLowerCase().includes(term) ||
            s.email?.toLowerCase().includes(term)
          );
        });

    // Sort alphabetically by last name, then first name
    return [...list].sort((a, b) => {
      const aLast = (a.lastName || a.name?.split(" ").pop() || "").toLowerCase();
      const bLast = (b.lastName || b.name?.split(" ").pop() || "").toLowerCase();
      if (aLast !== bLast) return aLast.localeCompare(bLast);
      const aFirst = (a.firstName || a.name?.split(" ").slice(0, -1).join(" ") || "").toLowerCase();
      const bFirst = (b.firstName || b.name?.split(" ").slice(0, -1).join(" ") || "").toLowerCase();
      return aFirst.localeCompare(bFirst);
    });
  }, [students, searchTerm]);

  // Pagination
  const totalItems = filteredStudents.length;
  const totalPages = Math.ceil(totalItems / rowsPerPage);
  const paginatedStudents = filteredStudents.slice(
    page * rowsPerPage,
    (page + 1) * rowsPerPage,
  );
  const startItem = totalItems > 0 ? page * rowsPerPage + 1 : 0;
  const endItem = Math.min((page + 1) * rowsPerPage, totalItems);

  function handleStudentClick(studentId: string) {
    if (courseId) {
      useStudentStore.getState().selectStudent(courseId, studentId);
      useCourseStore.getState().setStudentId(studentId);
      viewCourse(courseId, COURSE_VIEWS.STUDENT_SESSIONS as CourseView);
    }
  }

  function handleIconClick(
    e: React.MouseEvent,
    student: Student,
    session: any,
  ) {
    e.stopPropagation();
    const studentSession = student.sessions?.[session.id];
    setCheckinTarget({
      student,
      sessionId: session.id,
      sessionName: session.name || `Session`,
      studentSession: studentSession || null,
    });
  }

  async function handleToggleCheckIn(action: "check" | "uncheck" | "approve" | "deny") {
    if (!checkinTarget || !courseId) return;
    const { student, sessionId } = checkinTarget;
    const isCheckin = action === "check" || action === "approve";
    try {
      await checkUncheck({
        courseId,
        sessionId,
        checkin: isCheckin,
        attendeeid: student.id,
        method: CHECKIN_METHODS.MANUAL,
        code: "MANUAL",
        icon: 0,
        name: student.name || "",
        email: student.email || "",
        attendee_manual: student.attendee_manual ?? true,
      });
      // Optimistic local update — avoids full table refetch/rerender
      useStudentStore.setState((state) => ({
        students: state.students.map((s) => {
          if (s.id !== student.id) return s;
          const sessions = { ...s.sessions };
          if (isCheckin) {
            sessions[sessionId] = { ...(sessions[sessionId] || {}), checkin: true, request: "approved" };
          } else {
            delete sessions[sessionId];
          }
          return { ...s, sessions };
        }),
      }));
    } catch (err) {
      console.error("Check-in failed:", err);
    }
    setCheckinTarget(null);
  }

  function handleSelectAll(e: React.ChangeEvent<HTMLInputElement>) {
    if (e.target.checked) {
      setSelected(filteredStudents.map((s) => s.id));
    } else {
      setSelected([]);
    }
  }

  function handleItemChecked(studentId: string) {
    setSelected((prev) =>
      prev.includes(studentId)
        ? prev.filter((id) => id !== studentId)
        : [...prev, studentId],
    );
  }

  if (loading) {
    return (
      <div className="flex flex-col h-full">
        {/* Skeleton toolbar */}
        <div className="flex items-center gap-3 px-4 py-2 border-b" style={{ borderColor: "rgba(0,0,0,0.12)" }}>
          <Skeleton width={160} height={20} borderRadius={3} />
          <div className="flex-1" />
          <Skeleton width={160} height={24} borderRadius={3} />
        </div>
        {/* Skeleton rows */}
        <div className="px-2 py-2 space-y-3">
          {Array.from({ length: 6 }).map((_, i) => (
            <div key={i} className="flex items-center gap-3 px-2" style={{ height: 36 }}>
              <Skeleton width={16} height={16} borderRadius={3} />
              <Skeleton width={28} height={28} borderRadius="50%" />
              <Skeleton width={`${22 + (i % 3) * 6}%`} height={12} borderRadius={3} />
              <Skeleton width={`${18 + (i % 2) * 8}%`} height={12} borderRadius={3} />
              <Skeleton width={48} height={12} borderRadius={3} />
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      {/* Toolbar: title + menu + search */}
      <div
        className="flex items-center gap-3 px-4 py-2 border-b"
        style={{ borderColor: "rgba(0,0,0,0.12)" }}
      >
        <div className="flex items-center gap-1">
          <h3
            className="text-[17px] font-normal py-1"
            style={{ color: "#20486a" }}
          >
            Attendees {students.length ? `(${students.length})` : ""}
          </h3>
          <CourseStudentsMenu
            courseId={courseId || ""}
            selectedCount={selected.length}
            onAddStudent={() => setAddStudentOpen(true)}
            onDeleteSelected={() => setDeleteStudentsOpen(true)}
          >
            <button className="p-1 rounded-full hover:bg-gray-100 text-gray-500">
              <MoreVertical className="h-5 w-5" />
            </button>
          </CourseStudentsMenu>
        </div>

        <div className="flex-1" />

        {/* Search */}
        <div className="relative max-w-[200px]">
          <input
            type="text"
            placeholder="Search"
            value={searchTerm}
            onChange={(e) => startTransition(() => setSearchTerm(e.target.value))}
            className="w-full border-b border-gray-300 pb-1 text-sm focus:outline-none focus:border-blue-500 transition-colors pr-6"
          />
          <Search className="absolute right-0 bottom-2 h-4 w-4 text-gray-600" />
        </div>
      </div>

      {/* Students table */}
      {filteredStudents.length === 0 ? (
        <div className="flex flex-col items-center gap-2 py-16 text-center">
          <Users className="h-8 w-8 text-gray-300" />
          <p className="text-sm text-gray-500">
            {students.length === 0
              ? "No attendees enrolled"
              : "No matching attendees"}
          </p>
        </div>
      ) : (
        <div className="overflow-x-auto flex-1">
          <table className="w-full text-sm">
            <thead>
              <tr style={{ borderBottom: "1px solid rgba(0,0,0,0.2)" }}>
                {/* Checkbox header */}
                <th className="px-2 py-2 w-10">
                  <input
                    type="checkbox"
                    className="rounded border-gray-300"
                    checked={
                      selected.length === filteredStudents.length &&
                      filteredStudents.length > 0
                    }
                    onChange={handleSelectAll}
                  />
                </th>
                {/* Fixed columns — title case matching legacy */}
                <th className="px-3 py-2 text-left font-normal text-xs text-gray-500">
                  <span className="flex items-center gap-1">
                    Last name
                    <svg className="h-3 w-3 text-gray-400" viewBox="0 0 12 12" fill="currentColor">
                      <path d="M6 9L2 5h8L6 9z" />
                    </svg>
                  </span>
                </th>
                <th className="px-3 py-2 text-left font-normal text-xs text-gray-500">
                  First name
                </th>
                <th
                  className="px-3 py-2 text-center font-normal text-xs text-gray-500"
                  style={{ width: 100 }}
                >
                  Attendance<br />rate
                </th>
                {/* Per-session columns */}
                {sessionsCopy.map((session, index) => {
                  const date = session.begins
                    ? new Date(session.begins)
                    : null;
                  const tooltip = date
                    ? `${session.name || `Session ${index + 1}`}\n${date.toLocaleDateString("en-US", { year: "numeric", month: "short", day: "numeric" })}\n${date.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", hour12: false })}`
                    : session.name || `Session ${index + 1}`;
                  return (
                    <th
                      key={session.id}
                      className="px-1 py-2 text-center font-normal text-xs text-gray-500"
                      style={{ minWidth: 32 }}
                      title={tooltip}
                    >
                      {index + 1}
                    </th>
                  );
                })}
              </tr>
            </thead>
            <tbody>
              {paginatedStudents.map((student) => {
                // Parse name into first/last
                const firstName =
                  student.firstName ||
                  (student.name
                    ? student.name.split(" ").slice(0, -1).join(" ")
                    : "");
                const lastName =
                  student.lastName ||
                  (student.name ? student.name.split(" ").pop() : "Unknown");

                // Calculate attendance rate from sessions
                const studentSessions = student.sessions || {};
                const attendedCount = sessionsCopy.filter((s) => {
                  const entry = studentSessions[s.id];
                  return (
                    entry &&
                    entry.request !== "pending" &&
                    entry.request !== "denied"
                  );
                }).length;
                const rate =
                  sessionsCopy.length > 0
                    ? Math.round((attendedCount / sessionsCopy.length) * 100)
                    : 0;

                const isSelected = selected.includes(student.id);

                return (
                  <tr
                    key={student.id}
                    className="cursor-pointer hover:bg-gray-50 transition-colors"
                    style={{
                      height: 36,
                      borderBottom: "1px solid rgba(0,0,0,0.08)",
                    }}
                  >
                    {/* Checkbox */}
                    <td
                      className="px-2 text-center"
                      onClick={(e) => e.stopPropagation()}
                    >
                      <input
                        type="checkbox"
                        className="rounded border-gray-300"
                        checked={isSelected}
                        onChange={() => handleItemChecked(student.id)}
                      />
                    </td>
                    {/* Last Name with avatar */}
                    <td
                      className="px-3"
                      onClick={() => handleStudentClick(student.id)}
                    >
                      <div className="flex items-center gap-1.5">
                        <img
                          src={
                            student.picture ||
                            "/assets/images/icons/profile.jpg"
                          }
                          alt=""
                          className="h-7 w-7 rounded-full object-cover shrink-0"
                          onError={(e) => {
                            (e.target as HTMLImageElement).src =
                              "/assets/images/icons/profile.jpg";
                          }}
                        />
                        <span className="text-gray-700 truncate">
                          {lastName}
                        </span>
                      </div>
                    </td>
                    {/* First Name */}
                    <td
                      className="px-3 text-gray-700 truncate"
                      style={{ maxWidth: 190 }}
                      onClick={() => handleStudentClick(student.id)}
                    >
                      {firstName}
                    </td>
                    {/* Attendance Rate */}
                    <td
                      className="px-3 text-center font-medium text-gray-600"
                      onClick={() => handleStudentClick(student.id)}
                      style={!isPremium ? { filter: "blur(5px)", userSelect: "none" } : undefined}
                    >
                      {rate}%
                    </td>
                    {/* Per-session green/red circle icons — matching legacy */}
                    {sessionsCopy.map((session) => {
                      const entry = studentSessions[session.id];
                      const attended =
                        entry &&
                        entry.request !== "pending" &&
                        entry.request !== "denied";
                      return (
                        <td
                          key={session.id}
                          className="px-1 text-center"
                          style={{ minWidth: 32 }}
                          onClick={(e) => handleIconClick(e, student, session)}
                          title={`Click to ${attended ? "uncheck" : "check-in"} ${student.name}`}
                        >
                          {attended ? (
                            /* Green circle with checkmark — legacy style */
                            <svg className="h-5 w-5 mx-auto cursor-pointer" viewBox="0 0 24 24">
                              <circle cx="12" cy="12" r="10" fill="#4caf50" />
                              <path d="M9 12l2 2 4-4" stroke="white" strokeWidth="2.5" fill="none" strokeLinecap="round" strokeLinejoin="round" />
                            </svg>
                          ) : (
                            /* Red circle with X — legacy style */
                            <svg className="h-5 w-5 mx-auto cursor-pointer" viewBox="0 0 24 24">
                              <circle cx="12" cy="12" r="10" fill="#f44336" />
                              <path d="M8 8l8 8M16 8l-8 8" stroke="white" strokeWidth="2.5" fill="none" strokeLinecap="round" />
                            </svg>
                          )}
                        </td>
                      );
                    })}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* Pagination footer — matching legacy */}
      {totalItems > 0 && (
        <div
          className="flex items-center justify-end gap-4 px-4 py-2 text-xs text-gray-500 border-t"
          style={{ borderColor: "rgba(0,0,0,0.12)" }}
        >
          <span>Rows per Page</span>
          <select
            value={rowsPerPage}
            onChange={(e) => {
              setRowsPerPage(Number(e.target.value));
              setPage(0);
            }}
            className="border-none bg-transparent text-xs text-gray-600 cursor-pointer focus:outline-none"
          >
            {[10, 25, 50, 100].map((n) => (
              <option key={n} value={n}>{n}</option>
            ))}
          </select>
          <span>
            {startItem}-{endItem} of {totalItems}
          </span>
          <div className="flex items-center gap-1">
            <button
              disabled={page <= 0}
              onClick={() => setPage((p) => Math.max(0, p - 1))}
              className="p-1 rounded hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed"
            >
              <svg className="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M15 18l-6-6 6-6" />
              </svg>
            </button>
            <button
              disabled={page >= totalPages - 1}
              onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
              className="p-1 rounded hover:bg-gray-100 disabled:opacity-30 disabled:cursor-not-allowed"
            >
              <svg className="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M9 18l6-6-6-6" />
              </svg>
            </button>
          </div>
        </div>
      )}

      {/* Add Student Dialog */}
      {courseId && (
        <AddStudentDialog
          open={addStudentOpen}
          onOpenChange={setAddStudentOpen}
          courseId={courseId}
        />
      )}

      {/* Delete Students Dialog */}
      {courseId && (
        <DeleteStudentsDialog
          open={deleteStudentsOpen}
          onOpenChange={setDeleteStudentsOpen}
          courseId={courseId}
          students={students.filter((s) => selected.includes(s.id))}
        />
      )}

      {/* Manual Check-in Dialog */}
      {checkinTarget && (
        <ManualCheckInDialog
          open={!!checkinTarget}
          onOpenChange={(open) => { if (!open) setCheckinTarget(null); }}
          studentName={checkinTarget.student.name || ""}
          sessionName={checkinTarget.sessionName}
          studentSession={checkinTarget.studentSession}
          onToggleCheckIn={handleToggleCheckIn}
        />
      )}
    </div>
  );
}

