import { Skeleton } from "@/components/ui/skeleton";
import { CourseStudentsMenu } from "./CourseStudentsMenu";
import { AddStudentDialog } from "./AddStudentDialog";
import { DeleteStudentsDialog } from "./DeleteStudentsDialog";
import { ImportAttendeesDialog } from "./ImportAttendeesDialog";

// =========================================================================
// MAIN COMPONENT
// =========================================================================
export function FieldCourseStudents() {
  const courses = useCourseStore((s) => s.courses);
  const courseId = useCourseStore((s) => s.courseId);
  const checkins = useCourseStore((s) => s.checkins);
  const getCourseFieldCheckins = useCourseStore(
    (s) => s.getCourseFieldCheckins,
  );

  const course = courses?.find((c) => c.id === courseId);

  // Student detail drill-down
  const [selectedStudentId, setSelectedStudentId] = useState<string | null>(
    null,
  );
  const [searchTerm, setSearchTerm] = useState("");
  const [currentMonth, setCurrentMonth] = useState<Date>(new Date());

  // Bulk action state
  const [selected, setSelected] = useState<string[]>([]);
  const [addStudentOpen, setAddStudentOpen] = useState(false);
  const [deleteStudentsOpen, setDeleteStudentsOpen] = useState(false);
  const [importAttendeesOpen, setImportAttendeesOpen] = useState(false);

  // Students from the student store
  const storeStudents = useStudentStore((s) => s.students);
  const studentsLoading = useStudentStore((s) => s.loading);
  const getStudents = useStudentStore((s) => s.getCourseStudents);

  // Load field checkins + students on courseId change
  useEffect(() => {
    if (courseId) {
      getCourseFieldCheckins(courseId);
      getStudents(courseId);
    }
  }, [courseId, getCourseFieldCheckins, getStudents]);

  // Map store students to the format initFieldData expects
  const students = useMemo(
    () =>
      storeStudents.map((s) => ({
        id: s.id,
        name: s.name || `${s.firstName || ""} ${s.lastName || ""}`.trim(),
        firstName: s.firstName,
        lastName: s.lastName,
      })),
    [storeStudents],
  );

  // Derive all computed data via useMemo (React 19 pattern)
  const fieldData = useMemo(
    () => (students.length > 0 ? initFieldData(students, checkins) : null),
    [students, checkins],
  );

  const { months, studentsData, datesRow } = fieldData ?? {
    months: [] as Date[],
    studentsData: [],
    datesRow: [] as Date[],
  };

  // Auto-set currentMonth when fieldData changes
  useEffect(() => {
    if (fieldData) setCurrentMonth(fieldData.currentMonth);
  }, [fieldData]);

  // Filter dates for current month
  const visibleDates = useMemo(
    () => datesRow.filter((d) => isSameMonth(d, currentMonth)),
    [datesRow, currentMonth],
  );

  // Filtered students
  const filteredStudents = useMemo(() => {
    if (!searchTerm) return studentsData;
    const term = searchTerm.toLowerCase();
    return studentsData.filter((s) => s.name.toLowerCase().includes(term));
  }, [studentsData, searchTerm]);

  function handleSelectAll(e: React.ChangeEvent<HTMLInputElement>) {
    if (e.target.checked) {
      setSelected(filteredStudents.map((s) => s.id));
    } else {
      setSelected([]);
    }
  }

  function handleItemChecked(
    e: React.ChangeEvent<HTMLInputElement>,
    studentId: string,
  ) {
    e.stopPropagation();
    setSelected((prev) =>
      prev.includes(studentId)
        ? prev.filter((id) => id !== studentId)
        : [...prev, studentId],
    );
  }

  // --- Drill-down to student detail ---
  if (selectedStudentId) {
    const student = studentsData.find((s) => s.id === selectedStudentId);
    if (student && course) {
      return (
        <StudentFieldCheckinsView
          student={student}
          studentCheckins={student.checkins}
          course={course}
          onBack={() => setSelectedStudentId(null)}
        />
      );
    }
  }

  if (studentsLoading) {
    return (
      <div
        style={{
          height: "100%",
          display: "flex",
          flexDirection: "column",
          margin: theme.spacing.sm,
        }}
      >
        {/* Skeleton header */}
        <div
          style={{
            margin: "0 20px 4px 20px",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            padding: "8px 0",
          }}
        >
          <Skeleton width={160} height={20} borderRadius={3} />
          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <Skeleton width={200} height={28} borderRadius={4} />
            <Skeleton width={160} height={28} borderRadius={4} />
          </div>
        </div>
        {/* Skeleton table */}
        <div className="flex-1 overflow-hidden m-4 space-y-3">
          <div className="flex gap-3 items-center">
            <Skeleton width={130} height={14} borderRadius={3} />
            <Skeleton width={60} height={14} borderRadius={3} />
            <Skeleton width={80} height={14} borderRadius={3} />
            <Skeleton width={90} height={14} borderRadius={3} />
            {Array.from({ length: 7 }).map((_, i) => (
              <Skeleton key={i} width={36} height={28} borderRadius={3} />
            ))}
          </div>
          {Array.from({ length: 5 }).map((_, i) => (
            <div
              key={i}
              className="flex gap-3 items-center"
              style={{ height: 48 }}
            >
              <Skeleton width={130} height={12} borderRadius={3} />
              <Skeleton width={48} height={12} borderRadius={3} />
              <Skeleton width={64} height={12} borderRadius={3} />
              <Skeleton width={72} height={12} borderRadius={3} />
              {Array.from({ length: 7 }).map((_, j) => (
                <Skeleton key={j} width={36} height={20} borderRadius={3} />
              ))}
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div
      style={{
        height: "100%",
        display: "flex",
        flexDirection: "column",
        margin: theme.spacing.sm,
      }}
    >
      {/* Header: Title + Month Slider + Search */}
      <div
        style={{
          margin: "0 20px 4px 20px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          paddingTop: theme.spacing.xs,
          paddingBottom: theme.spacing.xs,
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: theme.spacing.sm,
            margin: theme.spacing.sm,
          }}
        >
          <span
            style={{
              fontWeight: theme.font.weight.medium,
              fontSize: "1.25rem",
              padding: 0,
              margin: 0,
            }}
          >
            Attendees{" "}
            {students.length > 0 && (
              <span
                style={{
                  fontWeight: theme.font.weight.normal,
                  color: theme.colors.text.hint,
                }}
              >
                ({students.length})
              </span>
            )}
          </span>
          <CourseStudentsMenu
            courseId={courseId || ""}
            selectedCount={selected.length}
            onAddStudent={() => setAddStudentOpen(true)}
            onDeleteSelected={() => setDeleteStudentsOpen(true)}
            onUploadList={() => setImportAttendeesOpen(true)}
          >
            <button
              style={{
                border: "none",
                background: "none",
                cursor: "pointer",
                padding: theme.spacing.xs,
                borderRadius: theme.radius.sm,
                display: "flex",
                alignItems: "center",
              }}
              title="More options"
            >
              <MoreVertical size={18} color="#666" />
            </button>
          </CourseStudentsMenu>
        </div>

        <div
          style={{
            display: "flex",
            alignItems: "flex-end",
            gap: theme.spacing.lg,
          }}
        >
          <MonthSlider
            months={months}
            value={currentMonth}
            onChange={setCurrentMonth}
          />
          <SearchInput
            value={searchTerm}
            onChange={(v) => startTransition(() => setSearchTerm(v))}
          />
        </div>
      </div>

      {/* Scrollable Table */}
      <div className="flex-1 overflow-y-auto m-4">
        <table style={TABLE_STYLE}>
          <thead style={{ position: "sticky", top: 0, zIndex: 10 }}>
            <tr>
              <th
                style={{
                  ...FIXED_HEADER_STYLE,
                  textAlign: "center",
                  width: 30,
                  padding: 0,
                  position: "sticky",
                  left: 0,
                  zIndex: 11,
                }}
              >
                <input
                  type="checkbox"
                  className="rounded border-gray-300"
                  checked={
                    selected.length === filteredStudents.length &&
                    filteredStudents.length > 0
                  }
                  onChange={handleSelectAll}
                />
              </th>
              <th
                style={{
                  ...FIXED_HEADER_STYLE,
                  textAlign: "center",
                  width: 70,
                  position: "sticky",
                  left: 30,
                  zIndex: 11,
                }}
              >
                Name
              </th>
              <th style={{ ...FIXED_HEADER_STYLE, width: 60 }}>Shifts</th>
              <th style={{ ...FIXED_HEADER_STYLE, width: 72 }}>
                Average Shift
              </th>
              <th style={{ ...FIXED_HEADER_STYLE, width: 72 }}>
                Total Duration
              </th>

              {visibleDates.map((date) => {
                const isToday = isSameDay(date, new Date());
                const endWeek = isEndOfWeek(date);
                const endMonth_ = isEndOfMonth(date);
                return (
                  <th
                    key={date.getTime()}
                    style={{
                      ...DATE_CELL_HEADER_STYLE,
                      background: isToday ? theme.colors.bg.today : "#f5f5f5",
                      color: "rgba(0, 0, 0, 0.87)",
                      borderBottom: "1px solid rgba(224, 224, 224, 1)",
                      borderRight:
                        endMonth_ || endWeek
                          ? "2px #a6a6a6 solid"
                          : "1px grey solid",
                    }}
                  >
                    <div
                      style={{
                        fontSize: theme.font.size.sm,
                        minWidth: 28,
                        display: "flex",
                        flexDirection: "column",
                      }}
                    >
                      {format(date, "EEE")}
                      <span
                        style={{
                          fontSize: 13,
                          fontWeight: theme.font.weight.bold,
                        }}
                      >
                        {format(date, "d")}
                      </span>
                    </div>
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody>
            {filteredStudents.map((student) => (
              <tr key={student.id} style={{ cursor: "pointer", height: 48 }}>
                <td
                  onClick={(e) => e.stopPropagation()}
                  style={{
                    ...FIXED_CELL_STYLE,
                    textAlign: "center",
                    position: "sticky",
                    left: 0,
                    zIndex: 5,
                    width: 30,
                    padding: 0,
                  }}
                >
                  <input
                    type="checkbox"
                    className="rounded border-gray-300"
                    checked={selected.includes(student.id)}
                    onChange={(e) => handleItemChecked(e, student.id)}
                  />
                </td>
                <td
                  onClick={() => setSelectedStudentId(student.id)}
                  style={{
                    ...FIXED_CELL_STYLE,
                    textAlign: "left",
                    position: "sticky",
                    left: 30,
                    zIndex: 5,
                  }}
                >
                  <div style={{ margin: "4px 0" }}>{student.name}</div>
                </td>

                <td
                  onClick={() => setSelectedStudentId(student.id)}
                  style={{ ...FIXED_CELL_STYLE, textAlign: "center" }}
                >
                  <div style={{ margin: "4px 0" }}>
                    {student.checkins.length > 0
                      ? student.checkins.length
                      : "-"}
                  </div>
                </td>

                <td
                  onClick={() => setSelectedStudentId(student.id)}
                  style={{ ...FIXED_CELL_STYLE, textAlign: "center" }}
                >
                  {student.checkins.length > 0
                    ? minutesToHourMinute(
                        student.totalShiftsDuration / student.checkins.length,
                        "hrs",
                        "min",
                      )
                    : "-"}
                </td>

                <td
                  onClick={() => setSelectedStudentId(student.id)}
                  style={{ ...FIXED_CELL_STYLE, textAlign: "center" }}
                >
                  {minutesToHourMinute(
                    student.totalShiftsDuration,
                    "hrs",
                    "min",
                  )}
                </td>

                {visibleDates.map((date) => {
                  const dayCheckins = student.checkins.filter((c) =>
                    areDatesOnSameDay(c.checkedInAt, date),
                  );
                  const isToday = isSameDay(date, new Date());
                  const endWeek = isEndOfWeek(date);
                  const endMonth_ = isEndOfMonth(date);
                  return (
                    <DataCellComp
                      key={date.getTime()}
                      checkins={dayCheckins}
                      student={student}
                      isToday={isToday}
                      endWeek={endWeek}
                      endMonth={endMonth_}
                    />
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>

        {filteredStudents.length === 0 && (
          <div
            style={{
              textAlign: "center",
              padding: theme.spacing.xl,
              color: "#999",
              fontSize: theme.font.size.base,
            }}
          >
            {students.length === 0
              ? "No attendees in this course."
              : "No matching attendees."}
          </div>
        )}
      </div>

      {/* Pagination footer */}
      <div
        style={{
          display: "flex",
          justifyContent: "flex-end",
          padding: `${theme.spacing.sm}px ${theme.spacing.md}px`,
          fontSize: 13,
          color: "#666",
          borderTop: `1px solid #eee`,
        }}
      >
        <span>
          {filteredStudents.length > 0
            ? `1-${filteredStudents.length} of ${filteredStudents.length}`
            : ""}
        </span>
      </div>
      {/* Dialogs */}
      {courseId && (
        <>
          <AddStudentDialog
            open={addStudentOpen}
            onOpenChange={setAddStudentOpen}
            courseId={courseId}
          />
          <DeleteStudentsDialog
            open={deleteStudentsOpen}
            onOpenChange={setDeleteStudentsOpen}
            courseId={courseId}
            students={students.filter((s) => selected.includes(s.id))}
          />
          <ImportAttendeesDialog
            open={importAttendeesOpen}
            onOpenChange={setImportAttendeesOpen}
            courseId={courseId}
          />
        </>
      )}
    </div>
  );
}

/**
 * Import Attendees from Excel Dialog
 * Replaces old ImportAttendeesExcelDialog.js (450 lines).
 * Handles reading XLSX files, mapping columns, validating phones/emails,
 * and bulk adding students via student.store.
 */

import React, { useState, useRef } from "react";
import { useTranslation } from "react-i18next";
import readXlsxFile from "read-excel-file/web";
import {
  Loader2,
  UploadCloud,
  AlertCircle,
  FileSpreadsheet,
} from "lucide-react";

import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { useStudentStore } from "../store/student.store";

interface ImportAttendeesExcelDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  courseId: string;
  courseName?: string;
}

const COLUMN_DEFINITIONS = [
  {
    key: "firstName",
    labels: ["first name", "given name", "personal name", "first", "שם פרטי"],
  },
  {
    key: "lastName",
    labels: ["last name", "family name", "surname", "last", "שם משפחה"],
  },
  {
    key: "email",
    labels: [
      "email",
      "mail",
      "e-mail",
      "email address",
      "electronic mail",
      "דואר אלקטרוני",
      'דוא"ל',
    ],
  },
  {
    key: "countryCode",
    labels: ["country code", "dial code", "country prefix", "קוד מדינה"],
  },
  {
    key: "phoneNumber",
    labels: [
      "phone number",
      "mobile",
      "phone",
      "cell phone",
      "telephone",
      "נייד",
      "טלפון נייד",
      "מספר נייד",
    ],
  },
  {
    key: "id",
    labels: [
      "id",
      "id number",
      "identity number",
      "identity card",
      "student id",
      "ת.ז.",
      "תעודת זהות",
      "מספר מזהה",
    ],
  },
];

export function ImportAttendeesExcelDialog({
  open,
  onOpenChange,
  courseId,
  courseName = "this course",
}: ImportAttendeesExcelDialogProps) {
  const { t } = useTranslation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const createStudentManual = useStudentStore((s) => s.createStudentManual);
  const getCourseStudents = useStudentStore((s) => s.getCourseStudents);

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [rows, setRows] = useState<any[]>([]); // parsed valid rows
  const [showPreview, setShowPreview] = useState(false);

  const [importing, setImporting] = useState(false);
  const [progress, setProgress] = useState(0);
  const [statusMessage, setStatusMessage] = useState("");

  function resetState() {
    setLoading(false);
    setError(null);
    setRows([]);
    setShowPreview(false);
    setImporting(false);
    setProgress(0);
    setStatusMessage("");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  }

  function handleOpenChange(isOpen: boolean) {
    if (!isOpen && importing) return; // Prevent closing while importing
    if (!isOpen) resetState();
    onOpenChange(isOpen);
  }

  async function handleFileUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;

    setError(null);
    setLoading(true);

    try {
      const data = await readXlsxFile(file);
      if (!data || data.length < 2) {
        throw new Error("No data rows found in the file.");
      }
      processExcelData(data);
    } catch (err: any) {
      console.error(err);
      setError(
        err.message ||
          "Invalid or empty file. Please upload a valid Excel file.",
      );
      setLoading(false);
    }
  }

  function processExcelData(data: any[]) {
    const headerRow = data[0].map((c: any) =>
      String(c || "")
        .trim()
        .toLowerCase(),
    );
    const dataRows = data.slice(1);

    const colMap: Record<string, number> = {};
    const missingColumns: string[] = [];
    let isCountryCodeMissing = false;

    // Detect columns
    COLUMN_DEFINITIONS.forEach((def) => {
      const idx = headerRow.findIndex((h: string) => def.labels.includes(h));
      if (idx === -1) {
        if (def.key === "countryCode") {
          isCountryCodeMissing = true;
        } else {
          missingColumns.push(def.labels[0]);
        }
      } else {
        colMap[def.key] = idx;
      }
    });

    if (missingColumns.length > 0) {
      setError(`Missing required columns: ${missingColumns.join(", ")}`);
      setLoading(false);
      return;
    }

    // Default country extraction heuristic (if missing)
    let defaultCountryCode = "1"; // Default to US
    if (isCountryCodeMissing) {
      const firstNameHeader = String(data[0][colMap["firstName"]]);
      const isHebrew = /[\u0590-\u05FF]/.test(firstNameHeader);
      defaultCountryCode = isHebrew ? "972" : "1";
    }

    // Check duplicate mappings
    const indices = Object.values(colMap);
    if (new Set(indices).size !== indices.length) {
      setError(
        "Duplicate column mappings detected. Each required column must be unique.",
      );
      setLoading(false);
      return;
    }

    const validRows: any[] = [];

    // Validate each row
    for (let i = 0; i < dataRows.length; i++) {
      const row = dataRows[i];
      const normalizedRow = COLUMN_DEFINITIONS.map((def) => {
        if (def.key === "countryCode" && isCountryCodeMissing) {
          return defaultCountryCode;
        }
        return row[colMap[def.key]];
      });

      // Avoid fully empty rows at the end of excel files
      if (
        normalizedRow.every(
          (val) => val === null || val === undefined || val === "",
        )
      ) {
        continue;
      }

      // Check missing data
      if (
        normalizedRow.some(
          (val) => val === undefined || val === null || val === "",
        )
      ) {
        setError(`Missing data in one or more columns in line ${i + 2}.`);
        setLoading(false);
        return;
      }

      const email = String(normalizedRow[2]);
      const emailRegex =
        /^(([^<>()[\]\.,;:\s@\"]+(\.[^<>()[\]\.,;:\s@\"]+)*)|(\".+\"))@(([^<>()[\]\.,;:\s@\"]+\.)+[^<>()[\]\.,;:\s@\"]{2,})$/i;
      if (!emailRegex.test(email)) {
        setError(`Invalid email "${email}" provided in line ${i + 2}.`);
        setLoading(false);
        return;
      }

      // Format country code
      normalizedRow[3] = String(normalizedRow[3] || "").replace(/[^0-9]/g, "");
      if (normalizedRow[3].length < 1) {
        setError(`No country code detected in line ${i + 2}.`);
        setLoading(false);
        return;
      }

      // Format phone
      normalizedRow[4] = String(normalizedRow[4] || "").replace(/[^0-9]/g, "");
      if (normalizedRow[4].length < 6) {
        setError(`Illegal phone number in line ${i + 2}.`);
        setLoading(false);
        return;
      }

      // Validate name
      if (
        String(normalizedRow[0]).trim().length < 1 ||
        String(normalizedRow[1]).trim().length < 1
      ) {
        setError(
          `Valid first and last name must be provided in line ${i + 2}.`,
        );
        setLoading(false);
        return;
      }

      // Valid ID
      if (String(normalizedRow[5]).trim().length < 1) {
        setError(`Attendee ID number must be provided in line ${i + 2}.`);
        setLoading(false);
        return;
      }

      validRows.push(normalizedRow);
    } // end for loop

    if (validRows.length === 0) {
      setError("No valid rows found to import.");
      setLoading(false);
      return;
    }

    setRows(validRows);
    setShowPreview(true);
    setLoading(false);
  }

  async function handleImport() {
    setImporting(true);
    let counter = 0;

    for (const student of rows) {
      counter++;
      setStatusMessage(
        `Processing attendee ${counter} out of ${rows.length}...`,
      );

      const newStudentData = {
        name: `${student[0]} ${student[1]}`, // Combine first and last name
        email: student[2],
        studentId: String(student[5]),
        phone: `+${student[3]}${String(student[4]).startsWith("0") ? student[4].substring(1) : student[4]}`,
        courseId,
      };

      try {
        await createStudentManual(courseId, newStudentData);
      } catch (err) {
        console.warn("Failed to create student manual", err);
        // The legacy app ignores individual failures and keeps going. We replicate this.
      }

      setProgress(Math.round((counter / rows.length) * 100));
    }

    // Refresh student list when done
    if (courseId) {
      await getCourseStudents(courseId);
    }

    handleOpenChange(false);
  }

  const headLabels = COLUMN_DEFINITIONS.map((def) =>
    def.labels[0].replace(/\b\w/g, (l) => l.toUpperCase()),
  );

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent className="sm:max-w-[700px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>
            {t("input attendees excel - dialog - title") ||
              "Import Attendees From Excel"}
          </DialogTitle>
        </DialogHeader>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-gray-400 mb-4" />
            <p className="text-sm text-gray-500">Reading Excel file...</p>
          </div>
        ) : importing ? (
          <div className="flex flex-col py-8 px-4">
            <div className="flex justify-between text-sm mb-2 text-gray-600">
              <span>{statusMessage}</span>
              <span>{progress}%</span>
            </div>
            <Progress value={progress} className="h-2 w-full bg-gray-100" />
          </div>
        ) : !showPreview ? (
          <div className="grid gap-6 py-4">
            <div className="text-sm text-gray-700 leading-relaxed">
              <p className="mb-4">
                You are about to import a list of attendees to{" "}
                <span className="font-semibold text-black">{courseName}</span>.
              </p>
              <p className="mb-2">
                The file must be in Excel format (.xlsx or .xls) and should
                contain the following columns:
              </p>
              <ul className="list-disc pl-5 mb-4 space-y-1 text-gray-600">
                <li>
                  <span className="font-semibold text-gray-800">
                    First Name
                  </span>{" "}
                  (or Given Name, First)
                </li>
                <li>
                  <span className="font-semibold text-gray-800">Last Name</span>{" "}
                  (or Family Name, Last)
                </li>
                <li>
                  <span className="font-semibold text-gray-800">Email</span>{" "}
                  (Institution Email address is preferable)
                </li>
                <li>
                  <span className="font-semibold text-gray-800">
                    Country Code
                  </span>{" "}
                  (optional; inferred if missing e.g. "1" for US)
                </li>
                <li>
                  <span className="font-semibold text-gray-800">
                    Phone Number
                  </span>{" "}
                  (without country code)
                </li>
                <li>
                  <span className="font-semibold text-gray-800">ID</span> (The
                  institutional Student identification number)
                </li>
              </ul>

              <div className="bg-blue-50 text-blue-800 text-xs px-3 py-2 rounded-md flex items-center gap-2 mb-4">
                <AlertCircle className="w-4 h-4" />
                <span className="font-medium">
                  Note: The primary attendee identifier is the phone number!
                </span>
              </div>
            </div>

            {error && (
              <Alert variant="destructive">
                <AlertCircle className="h-4 w-4" />
                <AlertDescription>{error}</AlertDescription>
              </Alert>
            )}

            <div className="flex justify-center mt-2">
              <Button
                onClick={() => fileInputRef.current?.click()}
                className="bg-link hover:bg-link/90 text-white flex gap-2 h-12 px-6"
              >
                <UploadCloud className="w-5 h-5" />
                {t(
                  "input attendees excel - dialog - select file button text",
                ) || "Select File"}
