        ) : (
          <div className="py-4">
            <div className="flex items-center gap-2 mb-4 text-link">
              <FileSpreadsheet className="w-5 h-5" />
              <span className="font-medium">
                Found {rows.length} valid attendees to import
              </span>
            </div>

            <div className="border rounded-md overflow-hidden bg-white max-h-[300px] overflow-y-auto">
              <table className="w-full text-sm text-left">
                <thead className="bg-gray-50 border-b text-gray-600 sticky top-0">
                  <tr>
                    {headLabels.map((h) => (
                      <th key={h} className="px-4 py-2 font-medium">
                        {h}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {rows.slice(0, 100).map((row, i) => (
                    <tr key={i} className="hover:bg-gray-50">
                      {row.map((cell: any, cIdx: number) => (
                        <td
                          key={cIdx}
                          className="px-4 py-2 text-gray-800 truncate max-w-[150px]"
                        >
                          {cell}
                        </td>
                      ))}
                    </tr>
                  ))}
                  {rows.length > 100 && (
                    <tr>
                      <td
                        colSpan={6}
                        className="px-4 py-3 text-center text-gray-500 text-xs italic"
                      >
                        ... and {rows.length - 100} more rows
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>

            <p className="text-xs text-gray-500 mt-4 text-center">
              Please review the data above. If everything looks correct, click
              Import to begin adding students.
            </p>
          </div>
        )}

        <DialogFooter className="mt-4 gap-2 sm:gap-0">
          <Button
            variant="ghost"
            onClick={() => handleOpenChange(false)}
            disabled={importing || loading}
            className="text-[#333] hover:bg-gray-100"
          >
            {t("common - cancel") || "Cancel"}
          </Button>
          {showPreview && !importing && (
            <Button
              onClick={handleImport}
              className="bg-link hover:bg-link/90 text-white"
            >
              Start Import
            </Button>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

/**
 * Import Grading Excel Dialog — import grades from Excel with attendance matching.
 * Replaces old ImportGradingExcelDialog.js (370 lines).
 *
 * Flow:
 * 1. Upload Excel file
 * 2. Find email column, match to enrolled students, compute attendance
 * 3. Display enriched table preview
 * 4. Download enriched Excel (CSV or XLSX) via ExcelJS
 */

import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import readXlsxFile from "read-excel-file/web";
import ExcelJS from "exceljs";
import { saveAs } from "file-saver";
import {
  Loader2,
  UploadCloud,
  AlertCircle,
  Download,
  FileSpreadsheet,
} from "lucide-react";

import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { useCourseStore } from "../store/course.store";
import { useStudentStore } from "../store/student.store";
import { getConfigExcelEmailPossibleTitles } from "@/shared/services/host.service";
import { getDateString } from "@/shared/utils/date.utils";

interface ImportGradingExcelDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  courseId: string;
  courseName?: string;
}

const NOT_FOUND_VALUE = "-";

// Default email column titles for auto-detection
const DEFAULT_EMAIL_TITLES = ["mail", "מייל", "דוא"];

export function ImportGradingExcelDialog({
  open,
  onOpenChange,
  courseId,
  courseName = "",
}: ImportGradingExcelDialogProps) {
  const { t } = useTranslation();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const courses = useCourseStore((s) => s.courses);
  const students = useStudentStore((s) => s.students);
  const [sessions, setSessions] = useState<any[]>([]);

  const [showTable, setShowTable] = useState(false);
  const [rows, setRows] = useState<any[][]>([]);
  const [importing, setImporting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [studentsNotFound, setStudentsNotFound] = useState(0);
  const [emailColumnTitles, setEmailColumnTitles] =
    useState<string[]>(DEFAULT_EMAIL_TITLES);
  const [titlesLoaded, setTitlesLoaded] = useState(false);

  // Resolve course name from store if not provided
  const resolvedCourseName =
    courseName ||
    (courses ?? []).find((c) => c.id === courseId)?.name ||
    "Course";

  // Load configurable email column titles
  useEffect(() => {
    if (open && !titlesLoaded) {
      setTitlesLoaded(true);
      getConfigExcelEmailPossibleTitles()
        .then((config: any) => {
          if (
            config?.status === "success" &&
            config?.result?.excelemailcolumntitles
          ) {
            setEmailColumnTitles([...config.result.excelemailcolumntitles]);
          }
        })
        .catch(() => {
          // use defaults
        });
    }
  }, [open, titlesLoaded]);

  // Load sessions for attendance matching
  useEffect(() => {
    if (open && courseId) {
      import("@/shared/services/session.service").then((mod) => {
        mod
          .getCourseSessions(courseId)
          .then((data: any) => {
            setSessions(Array.isArray(data) ? data : (data?.result ?? []));
          })
          .catch(() => setSessions([]));
      });
    }
  }, [open, courseId]);

  function resetState() {
    setShowTable(false);
    setRows([]);
    setImporting(false);
    setError(null);
    setStudentsNotFound(0);
    if (fileInputRef.current) fileInputRef.current.value = "";
  }

  function handleOpenChange(isOpen: boolean) {
    if (!isOpen) resetState();
    onOpenChange(isOpen);
  }

  function isMail(text: string): boolean {
    if (!text) return false;
    const lc = text.toLowerCase();
    return emailColumnTitles.some((title) => lc.includes(title));
  }

  function getAttendance(
    email: string,
    emailsNotFoundRef: { count: number },
  ): { appearances: string | number; attendanceRate: string | number } {
    const result = {
      appearances: NOT_FOUND_VALUE as string | number,
      attendanceRate: NOT_FOUND_VALUE as string | number,
    };

    if (!email || !students || !sessions) return result;

    const student = students.find(
      (s: any) =>
        s.email && s.email.toLowerCase() === String(email).toLowerCase(),
    );

    if (!student) {
      emailsNotFoundRef.count++;
      return result;
    }

    let appearances = 0;
    (sessions as any[]).forEach((session: any) => {
      (session.attendees ?? []).forEach((attendee: any) => {
        if (attendee.id === student.id) appearances++;
      });
    });

    const sessionCount = (sessions as any[]).length || 1;
    result.appearances = appearances;
    result.attendanceRate =
      Math.round((1000 * appearances) / sessionCount) / 10;
    return result;
  }

  async function handleFileUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;

    setError(null);
    setImporting(true);

    try {
      const data = await readXlsxFile(file);
      if (!data || data.length < 1) {
        throw new Error(
          t("import report error - email column not found") ||
            "No data found in the file.",
        );
      }
      processData(data as any[][]);
    } catch (err: any) {
      setError(err.message || "Failed to parse file.");
      setImporting(false);
    }
  }

  function processData(data: any[][]) {
    const headerRow = data[0];
    let emailIndex = -1;

    // Find email column
    headerRow.forEach((col: any, idx: number) => {
      if (isMail(String(col ?? ""))) emailIndex = idx;
    });

    if (emailIndex === -1) {
      setError(
        t("import report error - email column not found") ||
          "Email column not found in the uploaded file.",
      );
      setImporting(false);
      return;
    }

    // Build enriched table
    const emailsNotFoundRef = { count: 0 };
    const enrichedRows: any[][] = [];

    enrichedRows.push([
      ...headerRow,
      "Attendancies",
      "Attendance rate (percentage)",
      "grade",
    ]);

    for (let i = 1; i < data.length; i++) {
      const row = data[i];
      const padded: any[] = [];
      for (let j = 0; j < headerRow.length; j++) {
        padded.push(row[j] ?? "");
      }
      const email = String(row[emailIndex] ?? "");
      const { appearances, attendanceRate } = getAttendance(
        email,
        emailsNotFoundRef,
      );
      enrichedRows.push([...padded, appearances, attendanceRate]);
    }

    setStudentsNotFound(emailsNotFoundRef.count);
    setRows(enrichedRows);
    setImporting(false);
    setShowTable(true);
  }

  async function handleDownload(format: "csv" | "excel") {
    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet("Course Summary");

    rows.forEach((row, rowIdx) => {
      const excelRow = sheet.getRow(rowIdx + 1);
      excelRow.values = row;

      // Highlight rows where attendee was not found
      if (rowIdx > 0 && row[row.length - 1] === NOT_FOUND_VALUE) {
        row.forEach((_: any, colIdx: number) => {
          const cell = excelRow.getCell(colIdx + 1);
          cell.fill = {
            type: "pattern",
            pattern: "solid",
            fgColor: { argb: "FFFFFFCC" },
            bgColor: { argb: "FFFFFFCC" },
          };
        });
      }
    });

    // Auto-size columns
    if (rows.length > 0) {
      rows[0].forEach((_: any, colIdx: number) => {
        let maxLen = 10;
        rows.forEach((row) => {
          const len = String(row[colIdx] ?? "").length;
          if (len > maxLen) maxLen = len;
        });
        sheet.getColumn(colIdx + 1).width = Math.min(Math.max(maxLen, 10), 40);
      });
    }

    const fileName = `${resolvedCourseName} with attendance - ${getDateString(new Date())}`;

    if (format === "csv") {
      const buffer = await workbook.csv.writeBuffer();
      saveAs(new Blob([buffer]), `${fileName}.csv`);
    } else {
      const buffer = await workbook.xlsx.writeBuffer();
      saveAs(
        new Blob([buffer], {
          type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        }),
        `${fileName}.xlsx`,
      );
    }

    handleOpenChange(false);
  }

  const matchedCount = rows.length > 1 ? rows.length - 1 - studentsNotFound : 0;

  return (
    <Dialog open={open} onOpenChange={handleOpenChange}>
      <DialogContent className="sm:max-w-[800px] max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileSpreadsheet className="w-5 h-5" />
            {t("import report - title") || "Import Grading Report"}
            <span className="text-muted-foreground font-normal text-base ml-2">
              {resolvedCourseName}
            </span>
          </DialogTitle>
        </DialogHeader>

        {/* Loading state */}
        {importing && (
          <div className="flex flex-col items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-gray-400 mb-4" />
            <p className="text-sm text-gray-500">Processing file...</p>
          </div>
        )}

        {/* Upload step */}
        {!showTable && !importing && (
          <div className="grid gap-6 py-4">
            <div className="text-sm text-gray-700 leading-relaxed">
              <p className="mb-4">
                {t("import report - text") ||
                  "Upload your Excel file with student data. The system will match students by email and calculate attendance rates."}
              </p>
            </div>

            {error && (
              <Alert variant="destructive">
                <AlertCircle className="h-4 w-4" />
                <AlertDescription>{error}</AlertDescription>
              </Alert>
            )}

            <div className="flex justify-center">
              <Button
                onClick={() => fileInputRef.current?.click()}
                className="bg-link hover:bg-link/90 text-white flex gap-2 h-12 px-6"
              >
                <UploadCloud className="w-5 h-5" />
                {t(
                  "input attendees excel - dialog - select file button text",
                ) || "Select File"}
              </Button>
              <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileUpload}
                accept=".xls,.xlsx"
                className="hidden"
              />
            </div>
          </div>
        )}

        {/* Preview table */}
        {showTable && !error && (
          <div className="py-2">
            <div className="border rounded-md overflow-hidden bg-white max-h-[400px] overflow-y-auto">
              <table className="w-full text-xs text-left">
                <thead className="bg-gray-50 border-b text-gray-600 sticky top-0">
                  <tr>
                    {rows[0]?.map((h: any, i: number) => (
                      <th
                        key={i}
                        className="px-3 py-2 font-medium whitespace-nowrap"
                      >
                        {String(h)}
                      </th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {rows.slice(1, 201).map((row, rIdx) => (
                    <tr
                      key={rIdx}
                      className={
                        row[row.length - 1] === NOT_FOUND_VALUE
                          ? "bg-yellow-50"
                          : "hover:bg-gray-50"
                      }
                    >
                      {row.map((cell: any, cIdx: number) => (
                        <td
                          key={cIdx}
                          className="px-3 py-1.5 text-gray-800 truncate max-w-[150px]"
                        >
                          {String(cell ?? "")}
                        </td>
                      ))}
                    </tr>
                  ))}
                  {rows.length > 201 && (
                    <tr>
                      <td
                        colSpan={rows[0]?.length}
                        className="px-3 py-2 text-center text-gray-500 text-xs italic"
                      >
                        ... and {rows.length - 201} more rows
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

        <DialogFooter className="gap-2 flex-col sm:flex-row">
          {!showTable || error ? (
            <Button variant="outline" onClick={() => handleOpenChange(false)}>
              {t("common - cancel") || "Cancel"}
            </Button>
          ) : (
            <>
              <div className="text-sm text-gray-700 mr-auto">
                <span className="font-semibold">{matchedCount}</span> attendees
                matched.{" "}
                <span className="text-amber-600 font-semibold">
                  {studentsNotFound}
                </span>{" "}
                not recognized.
              </div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={() => handleDownload("csv")}
                  className="flex gap-1"
                >
                  <Download className="w-4 h-4" />
                  CSV
                </Button>
                <Button
                  onClick={() => handleDownload("excel")}
                  className="bg-link hover:bg-link/90 text-white flex gap-1"
                >
                  <Download className="w-4 h-4" />
                  Excel
                </Button>
              </div>
            </>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

/**
 * ImportSessionsFromExcelDialog
 * Mirrors legacy ImportSessionsFromExcelDialog.js.
 * Multi-step: 1) Instructions + file upload, 2) Preview parsed sessions, 3) Import with progress.
 * Expects Excel with columns: Session Name, Date, Time.
 */

import { useState, useRef } from "react";
import { useTranslation } from "react-i18next";
import { Upload, Loader2, AlertCircle } from "lucide-react";
import { format } from "date-fns";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";

interface ParsedSession {
  name: string;
  date: string;
  time: string;
}

interface ImportSessionsFromExcelDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  courseName: string;
  onImport: (sessions: ParsedSession[]) => Promise<void>;
}

const EXPECTED_COLUMNS = ["Session Name", "Date", "Time"];

export function ImportSessionsFromExcelDialog({
  open,
  onOpenChange,
  courseName,
  onImport,
}: ImportSessionsFromExcelDialogProps) {
  const { t } = useTranslation();
  const fileRef = useRef<HTMLInputElement>(null);
  const [sessions, setSessions] = useState<ParsedSession[]>([]);
  const [showTable, setShowTable] = useState(false);
  const [importing, setImporting] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState("");

  const handleFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setError(null);

    try {
      // Dynamic import to keep bundle small
      const { read, utils } = await import("xlsx");
      const data = await file.arrayBuffer();
      const wb = read(data);
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows: unknown[][] = utils.sheet_to_json(ws, { header: 1 });

      if (!rows || rows.length < 2) {
        setError("File must have at least a header row + one data row.");
        return;
      }

      const header = (rows[0] as string[]).map((h) =>
        (h || "").toString().trim().toLowerCase(),
      );
      for (let i = 0; i < EXPECTED_COLUMNS.length; i++) {
        if (header[i] !== EXPECTED_COLUMNS[i].toLowerCase()) {
          setError(
            `Wrong column. Expected "${EXPECTED_COLUMNS[i]}" but got "${rows[0][i] || "(empty)"}"`,
          );
          return;
        }
      }

      const parsed: ParsedSession[] = [];
      for (let r = 1; r < rows.length; r++) {
        const row = rows[r] as unknown[];
        if (!row || row.length < 3) continue;

        let name = String(row[0] || "").substring(0, 20);
        if (name.length < 1) {
          setError(`Error: Illegal session name in line ${r + 1}.`);
          return;
        }

        // Date handling — could be serial number or string
        let dateStr: string;
        if (typeof row[1] === "number") {
          const startDate = new Date("1/1/1900 00:00");
          startDate.setDate(startDate.getDate() + (row[1] as number) - 2);
          dateStr = format(startDate, "EEEE, MMM dd yyyy");
        } else {
          dateStr = format(new Date(row[1] as string), "EEEE, MMM dd yyyy");
        }

        // Time handling
        let timeStr: string;
        if (typeof row[2] === "number") {
          const totalHours = (row[2] as number) * 24;
          const h = Math.floor(totalHours);
          const m = Math.round((totalHours - h) * 60);
          timeStr = `${h.toString().padStart(2, "0")}:${m.toString().padStart(2, "0")}`;
        } else {
          timeStr = String(row[2]);
        }

        parsed.push({ name, date: dateStr, time: timeStr });
      }

      setSessions(parsed);
      setShowTable(true);
    } catch (err) {
      setError(
        "Failed to parse Excel file. Make sure it is a valid .xlsx file.",
      );
    }
  };

  const handleImport = async () => {
    setImporting(true);
    setShowTable(false);
    try {
      for (let i = 0; i < sessions.length; i++) {
        setMessage(`Processing session ${i + 1} out of ${sessions.length}`);
        setProgress(((i + 1) / sessions.length) * 100);
      }
      await onImport(sessions);
      onOpenChange(false);
    } finally {
      setImporting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[600px]">
        <DialogHeader>
          <DialogTitle>
            {t("session-actions - import sessions dialog - title")}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4 py-2 text-sm">
          {/* Error */}
          {error && (
            <div className="flex items-start gap-2 p-3 bg-red-50 border border-red-200 rounded text-red-700">
              <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
              <span>{error}</span>
            </div>
          )}

          {/* Instructions step */}
          {!showTable && !importing && !error && (
            <div className="space-y-3">
              <p>
                {t("session-actions - import sessions dialog - text 1")}
                <strong className="text-link"> {courseName} </strong>
                {t("session-actions - import sessions dialog - text 2")}
              </p>
              <p>
                To run these sessions, hover over their names and click &quot;
                <strong>Resume Session</strong>&quot;.
              </p>
              <div className="text-xs text-gray-500 space-y-1">
                <p>Please note:</p>
                <ol className="list-decimal ml-5 space-y-0.5">
                  <li>
                    Sessions with future dates will not be visible in the
                    attendees App, so they will not be counted as absences.
                  </li>
                  <li>
                    After a session has been run, the session time and date will
                    be updated to reflect the actual running time.
                  </li>
                </ol>
              </div>
              <p>
                Upload an Excel file with columns: <strong>Session Name</strong>
                , <strong>Date</strong>, <strong>Time</strong>. Names can be up
                to 20 characters.
              </p>

              <Button
                onClick={() => fileRef.current?.click()}
                variant="outline"
              >
                <Upload className="w-4 h-4 mr-2" />
                Select File
              </Button>
              <input
                type="file"
                accept=".xlsx,.xls"
                hidden
                ref={fileRef}
                onChange={handleFile}
              />
            </div>
          )}

          {/* Preview table */}
          {showTable && !error && (
            <div className="border rounded-lg overflow-auto max-h-[300px]">
              <table className="w-full text-sm">
                <thead className="bg-gray-50 sticky top-0">
                  <tr>
                    <th className="p-2 text-left">#</th>
                    <th className="p-2 text-left">Session Name</th>
                    <th className="p-2 text-left">Date</th>
                    <th className="p-2 text-left">Time</th>
                  </tr>
                </thead>
                <tbody>
                  {sessions.map((s, i) => (
                    <tr key={i} className="border-t">
                      <td className="p-2 text-gray-400">{i + 1}</td>
                      <td className="p-2">{s.name}</td>
                      <td className="p-2">{s.date}</td>
                      <td className="p-2">{s.time}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Import progress */}
          {importing && (
            <div className="space-y-2 text-center">
              <p className="text-sm text-gray-600">{message}</p>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div
                  className="bg-link h-2 rounded-full transition-all"
                  style={{ width: `${progress}%` }}
                />
              </div>
            </div>
          )}
        </div>

        <DialogFooter>
          {(!showTable || error) && (
            <Button variant="ghost" onClick={() => onOpenChange(false)}>
              Cancel
            </Button>
          )}
          {showTable && !error && (
            <Button onClick={handleImport} disabled={importing}>
              {importing ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                "Import"
              )}
            </Button>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

