            width: "100%",
          }}
        >
          {/* Title bar */}
          <div
            style={{
              width: "100%",
              display: "flex",
              justifyContent: "center",
              alignItems: "center",
              padding: "14px 0",
              fontWeight: 700,
              fontSize: 15,
            }}
          >
            Download Printable Course Sign
          </div>

          {/* Inner sign page — the printable area */}
          <div
            ref={signRef}
            style={{
              width: "78%",
              background: "#ECF0F3",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              paddingBottom: 16,
            }}
          >
            {/* Institute logo bar */}
            <div
              style={{
                width: "100%",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: "8px 12px",
                backgroundColor: themeBgColor,
              }}
            >
              {logoImage ? (
                <img
                  src={logoImage}
                  alt="Institute Logo"
                  style={{ maxHeight: 36, objectFit: "contain" }}
                  crossOrigin="anonymous"
                />
              ) : (
                <span style={{ color: "#fff", fontSize: 13, fontWeight: 500, letterSpacing: "0.5px" }}>
                  Your Logo Goes Here*
                </span>
              )}
            </div>

            {/* Course name */}
            <div
              style={{
                color: "#224b6f",
                fontWeight: 700,
                fontSize: 18,
                textAlign: "center",
                padding: "12px 8px 8px",
              }}
            >
              {courseName}
            </div>

            {/* QR Code with EZ✓ME logo overlay */}
            <div
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                padding: "4px 0 8px",
              }}
            >
              <div
                style={{
                  position: "relative",
                  padding: 4,
                  background: "#fff",
                  boxShadow:
                    "0px 5px 5px -3px rgba(0,0,0,0.2), 0px 8px 10px 1px rgba(0,0,0,0.14), 0px 3px 14px 2px rgba(0,0,0,0.12)",
                }}
              >
                <QRCodeCanvas
                  value={qrUrl}
                  size={260}
                  level="H"
                  includeMargin={false}
                  style={{ display: "block" }}
                />
                {/* Center logo overlay */}
                <div
                  style={{
                    position: "absolute",
                    inset: 0,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    pointerEvents: "none",
                  }}
                >
                  <img
