                    : locStatus === "remote"
                      ? "text-red-500"
                      : "text-gray-400";

                return (
                  <tr
                    key={student.id}
                    onClick={() => handleStudentClick(student.id)}
                    className="cursor-pointer hover:bg-gray-50 transition-colors"
                    style={{
                      height: 48,
                      borderBottom: "1px solid rgba(0,0,0,0.08)",
                    }}
                  >
                    {/* ── C1/D1 — Avatar + Name ── */}
                    <td className="px-4">
                      <div className="flex items-center gap-2">
                        <img
                          width={40}
                          height={40}
