                    <td className="px-4">
                      <div
                        className="flex items-center gap-2 cursor-pointer"
                        onClick={(e) => {
                          e.stopPropagation();
                          setCheckinStudent({
                            id: student.id,
                            name: student.name,
                            email: student.email,
                            attendee_manual: student.attendee_manual,
                            sessionData: student.sessions?.[sessionId!] ?? null,
                          });
                        }}
                      >
                        {/* ✅ or ❌ icon */}
                        <XVIcon
                          checked={isCheckedIn}
                          request={student.request}
                        />
                        {isCheckedIn ? (
                          <span className="text-gray-700">
                            {student.checkinTime
                              ? new Date(
                                  student.checkinTime,
                                ).toLocaleString("en-US", {
                                  year: "numeric",
                                  month: "short",
                                  day: "numeric",
                                  hour: "2-digit",
                                  minute: "2-digit",
                                  hour12: false,
                                })
