                          <span className="text-blue-600 underline hover:text-blue-800 text-sm">
                            Check-in...
                          </span>
                        )}
                      </div>
                    </td>

                    {/* ── C4 — Check-in method (TEXT, not icon) ── */}
                    <td className="px-4">
                      {isCheckedIn && methodText ? (
                        <span className="underline text-gray-700 cursor-pointer">
                          {methodText}
                        </span>
                      ) : null}
                    </td>

