                        >
                          <MapPin className="h-4 w-4" />
                          <span>{locText}</span>
                        </span>
                      ) : null}
                    </td>

                    <td />
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* ═══ E — FOOTER ══════════════════════════════════════ */}
      <div
        className="flex items-center justify-between px-4 py-2 border-t border-gray-200 text-sm shrink-0"
        style={{ minHeight: 48 }}
      >
        {/* E1/E2 — Previous / Next Session links */}
        <div className="flex items-center gap-4">
          <button
            onClick={() => navigateSession("prev")}
            disabled={!prevSession}
            className={cn(
              "text-blue-600 hover:underline",
              !prevSession && "text-gray-400 cursor-not-allowed no-underline",
            )}
          >
            Previous Session
          </button>
          <button
            onClick={() => navigateSession("next")}
            disabled={!nextSession}
            className={cn(
              "text-blue-600 hover:underline",
              !nextSession && "text-gray-400 cursor-not-allowed no-underline",
            )}
          >
            Next Session
          </button>
        </div>

        {/* E3 — Rows per Page + pagination */}
        <div className="flex items-center gap-3 text-gray-600">
          <span>Rows per Page</span>
          <select
            value={rowsPerPage}
            onChange={(e) => {
              setRowsPerPage(Number(e.target.value));
              setPage(0);
            }}
            className="border border-gray-300 rounded px-1 py-0.5 text-sm bg-white"
          >
            {[10, 25, 50, 100].map((n) => (
              <option key={n} value={n}>
                {n}
              </option>
            ))}
          </select>
          <span className="text-gray-500">
            {startRow}-{endRow} of {totalStudents}
          </span>
          <button
            onClick={() => setPage((p) => Math.max(0, p - 1))}
            disabled={page === 0}
            className={cn(
              "p-0.5 rounded hover:bg-gray-100",
              page === 0 && "opacity-30 cursor-not-allowed",
            )}
          >
            <ChevronLeft className="h-4 w-4" />
          </button>
          <button
            onClick={() => setPage((p) => Math.min(maxPage, p + 1))}
            disabled={page >= maxPage}
            className={cn(
              "p-0.5 rounded hover:bg-gray-100",
              page >= maxPage && "opacity-30 cursor-not-allowed",
            )}
          >
            <ChevronRight className="h-4 w-4" />
          </button>
        </div>
      </div>

      {/* ═══ Dialogs ═════════════════════════════════════════ */}
      <CheckinImageDialog
        open={!!checkinImage}
        onOpenChange={(open) => {
          if (!open) setCheckinImage(null);
        }}
        imageUrl={checkinImage?.url ?? ""}
        date={checkinImage?.date ?? ""}
      />

      <StartSessionDialog
        open={resumeDialogOpen}
        onOpenChange={(open) => !open && setResumeDialogOpen(false)}
        resumedSession={session}
        onSessionStarted={(session) => {
          setResumeDialogOpen(false);
          try {
            document.documentElement.requestFullscreen?.().catch(() => {});
          } catch (error) {
            console.error("[SessionStudents] Fullscreen not available", error);
          }
          navigate({
            to: "/session/$shortid",
            params: {
              shortid:
                session.shortId ||
                session.shortid ||
                session.id,
            },
          });
        }}
      />

      <ManualCheckInDialog
        open={!!checkinStudent}
        onOpenChange={(open) => { if (!open) setCheckinStudent(null); }}
        studentName={checkinStudent?.name ?? ""}
        sessionName={session?.name || `Session ${session?.serialId ?? ""}`}
        studentSession={checkinStudent?.sessionData}
        onToggleCheckIn={async (action) => {
          if (!courseId || !sessionId || !checkinStudent) return;

          if (action === "approve" || action === "deny") {
            // Late check-in request: update the request status
            const updatedStudent = allStudents.find(s => s.id === checkinStudent.id);
            if (updatedStudent?.sessions?.[sessionId]) {
              updatedStudent.sessions[sessionId].request = action === "approve" ? "approved" : "denied";
            }
          }

          const isCheckin = action === "check" || action === "approve";

          await checkUncheck({
            courseId,
            sessionId,
            checkin: isCheckin,
            attendeeid: checkinStudent.id,
            method: CHECKIN_METHODS.MANUAL,
            code: "MANUAL",
            icon: 0,
            name: checkinStudent.name,
            email: checkinStudent.email,
            attendee_manual: checkinStudent.attendee_manual,
          });
          // Re-fetch to update the view
          await getCourseStudents(courseId);
          setCheckinStudent(null);
        }}
      />
    </div>
  );
}

/**
 * DataCellComp — Renders shift bars for a single day/student cell in the calendar grid.
 */

import { useState, useEffect, useRef } from "react";
import { FieldCheckinBar } from "./FieldCheckinBar";
import { areDatesOnSameDay } from "../../utils/field-course.utils";
import type { StudentData } from "../../utils/field-course.utils";
import type { FieldCheckin } from "@/shared/types";

interface DataCellProps {
  checkins: FieldCheckin[];
  student: StudentData;
  isToday: boolean;
  endWeek: boolean;
  endMonth: boolean;
}

export function DataCellComp({
  checkins,
  student,
  isToday,
  endWeek,
  endMonth,
}: DataCellProps) {
  const cellRef = useRef<HTMLTableCellElement>(null);
  const [dims, setDims] = useState({ w: 0, h: 0 });

  useEffect(() => {
    const el = cellRef.current;
    if (!el) return;
    const ro = new ResizeObserver(([entry]) => {
      const { width, height } = entry.contentRect;
      setDims({ w: width, h: height });
    });
    ro.observe(el);
    return () => ro.disconnect();
  }, []);

  return (
    <td
      ref={cellRef}
      style={{
        padding: 0,
        position: "relative",
        verticalAlign: "top",
        border: "1px grey solid",
        textAlign: "center",
        background: isToday ? "#e9e9e9" : "transparent",
        borderRight:
          endMonth || endWeek ? "2px #a6a6a6 solid" : "1px grey solid",
        minWidth: 28,
      }}
    >
      <div
        style={{
          display: "flex",
          flexDirection: "row",
          justifyContent: "center",
        }}
      >
        {checkins.length === 0 ? (
          <div>&nbsp;</div>
        ) : (
          checkins.map((checkin, idx) => (
            <div
              key={checkin._id || `checkin-${idx}`}
              style={{
                margin: "4px 0",
                display: "flex",
                alignItems: "flex-start",
              }}
            >
              <FieldCheckinBar
                checkin={checkin}
                student={student}
                cellWidth={dims.w}
                cellHeight={dims.h}
              />
            </div>
          ))
        )}
      </div>
    </td>
  );
}

// Re-export areDatesOnSameDay for the parent to use when filtering
export { areDatesOnSameDay };

