/**
 * FieldCheckinBar — The green/orange/red shift bar in the calendar grid.
 * Renders a positioned bar with hover tooltip.
 */

import { useState, useRef } from "react";
import { ShiftTooltip } from "./ShiftTooltip";
import { theme } from "@/config/theme";
import type { StudentData } from "../../utils/field-course.utils";
import type { FieldCheckin } from "@/shared/types";

interface FieldCheckinBarProps {
  checkin: FieldCheckin;
  student: StudentData;
  cellWidth: number;
  cellHeight: number;
}

const BAR_MIN_WIDTH = 4;

function getBarColor(checkin: FieldCheckin): string {
  if (checkin.request === "denied") return theme.colors.field.denied;
  if (checkin.request === "pending") return theme.colors.field.pending;
  if (!checkin.checkedOutAt) return theme.colors.field.openShift;
  return theme.colors.field.ok;
}

function getHoverColor(checkin: FieldCheckin): string {
  if (checkin.request === "pending") return theme.colors.field.pendingHover;
  if (checkin.request === "denied") return theme.colors.field.deniedHover;
  return theme.colors.field.okHover;
}

export function FieldCheckinBar({
  checkin,
  student,
  cellWidth,
  cellHeight,
}: FieldCheckinBarProps) {
  const [showTooltip, setShowTooltip] = useState(false);
  const barRef = useRef<HTMLDivElement>(null);
  const enterTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const leaveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const width = (() => {
    const end = checkin.checkedOutAt ?? Date.now();
    const w = (cellWidth * (end - checkin.checkedInAt)) / 86400000;
    return Math.max(w, BAR_MIN_WIDTH);
  })();

  const left = (() => {
    const startTime = new Date(checkin.checkedInAt);
    const minutesPassed = startTime.getHours() * 60 + startTime.getMinutes();
    return (cellWidth * minutesPassed) / 24 / 60;
  })();

  const color = getBarColor(checkin);
  const hover = getHoverColor(checkin);

  return (
    <div
      ref={barRef}
      onMouseEnter={() => {
        if (leaveTimerRef.current) clearTimeout(leaveTimerRef.current);
        enterTimerRef.current = setTimeout(() => setShowTooltip(true), 300);
      }}
      onMouseLeave={() => {
        if (enterTimerRef.current) clearTimeout(enterTimerRef.current);
        leaveTimerRef.current = setTimeout(() => setShowTooltip(false), 300);
      }}
      style={{
        position: "absolute",
        zIndex: 10,
        height: Math.max(cellHeight - 9, 0),
        width,
        background: color,
        left,
        top: 4,
        cursor: "pointer",
        transition: "background 0.15s",
      }}
      onMouseOver={(e) =>
        ((e.currentTarget as HTMLElement).style.background = hover)
      }
      onMouseOut={(e) =>
        ((e.currentTarget as HTMLElement).style.background = color)
      }
    >
      {showTooltip && barRef.current && (
        <div
          style={{
            position: "fixed",
            zIndex: 10000,
            top: (() => {
              const rect = barRef.current!.getBoundingClientRect();
              const isUpperHalf = rect.top < window.innerHeight * 0.5;
              // left-start: align top of tooltip with top of bar
              // left-end: tooltip appears above the bar
              return isUpperHalf ? rect.top : rect.bottom - 8;
            })(),
            left: barRef.current.getBoundingClientRect().left - 370,
            pointerEvents: "none",
          }}
        >
          <ShiftTooltip checkin={checkin} student={student} />
        </div>
      )}
    </div>
  );
}

/**
 * ShiftTooltip — Hover tooltip for field checkin bars.
 * Shows shift duration, check-in/out times, and status.
 */

import { format, differenceInMinutes } from "date-fns";
import { theme } from "@/config/theme";
import { getFieldCheckinStatus } from "../../utils/field-course.utils";
import type { StudentData } from "../../utils/field-course.utils";
import type { FieldCheckin } from "@/shared/types";

interface ShiftTooltipProps {
  checkin: FieldCheckin;
  student: StudentData;
}

export function ShiftTooltip({ checkin, student }: ShiftTooltipProps) {
  const getTimeDiffStr = (start: number, end: number) => {
    const dif = differenceInMinutes(new Date(end), new Date(start));
    const hours = Math.floor(dif / 60);
    const minutes = dif - hours * 60;
    return `${hours}:${minutes > 9 ? minutes : "0" + minutes}`;
  };

  const { status, color } = getFieldCheckinStatus(checkin);

  return (
    <div
      style={{
        background: theme.colors.slider.bubble,
        color: theme.colors.text.white,
        padding: "10px 14px",
        borderRadius: 6,
        fontSize: 13,
        lineHeight: "20px",
        zIndex: 9999,
        display: "flex",
        flexDirection: "column",
        justifyContent: "flex-start",
      }}
    >
      {/* Title section — two-column layout matching legacy */}
      <div
        style={{
          display: "flex",
          flexDirection: "row",
          margin: 5,
          width: 340,
          paddingBottom: 11,
          borderBottom: "1px solid rgba(255,255,255,0.3)",
        }}
      >
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            width: "50%",
            justifyContent: "flex-start",
          }}
        >
          <div style={{ fontWeight: theme.font.weight.semibold }}>
            {student.name}
          </div>
          <div>
            Shift duration:{" "}
            {checkin.checkedOutAt
              ? getTimeDiffStr(checkin.checkedInAt, checkin.checkedOutAt)
              : `${getTimeDiffStr(checkin.checkedInAt, Date.now())} (in progress)`}
          </div>
        </div>
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            width: "50%",
            justifyContent: "flex-start",
          }}
        >
          {checkin.request && (
            <>
              <div>Late check-in request: {checkin.request}</div>
              {checkin.reason && <div>Reason: {checkin.reason}</div>}
            </>
          )}
        </div>
      </div>
      {/* Check-in / Check-out details — side by side */}
      <div style={{ display: "flex", flexDirection: "row", marginTop: 10 }}>
        <div style={{ display: "flex", flexDirection: "column", margin: 5 }}>
          <div>
            Checked-in:{" "}
            {format(new Date(checkin.checkedInAt), "MMM d yyyy, HH:mm")}
          </div>
        </div>
        <div style={{ display: "flex", flexDirection: "column", margin: 5 }}>
          <div>
            Checked-out:{" "}
            {checkin.checkedOutAt
              ? format(new Date(checkin.checkedOutAt), "MMM d yyyy, HH:mm")
              : "Shift in Progress..."}
          </div>
        </div>
      </div>
      <div style={{ marginTop: 4, margin: 5, color }}>{status}</div>
    </div>
  );
}

/**
 * Session InfoPane
 * Mirrors legacy Session/InfoPane.js, Instructions.js, StudentsCounter.js.
 * Left pane of the live session screen showing:
 * - Theme logo (branded sessions)
 * - Course name and session name
 * - Yellow instruction strip with session shortid
 * - Students counter with animated name display
 */

import { memo, useEffect, useRef, useState } from "react";
import { useTranslation } from "react-i18next";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface SessionTheme {
  image?: string;
  color?: string;
}

interface SessionData {
  shortid: string | number;
  coursename: string;
  name: string;
  language?: string;
  theme: SessionTheme;
}

interface InfoPaneProps {
  session: SessionData;
  visibleAttendeeName?: string;
  initialCount: number;
  nameCounter: number;
  isWaiting: boolean;
  visibleText?: string;
  iconQuizEnabled?: boolean;
  ivrEnabled?: boolean;
}

// ---------------------------------------------------------------------------
// Instructions sub-components
// ---------------------------------------------------------------------------

const IvrInstructions = memo(
  ({ ivrEnabled, isRtl }: { ivrEnabled?: boolean; isRtl: boolean }) => {
    const { t } = useTranslation();
    if (!ivrEnabled) return null;
    return (
      <h3 className={`text-lg ${isRtl ? "text-right" : ""}`}>
        {t("session ivr call instruction")}
      </h3>
    );
  },
);

const SessionIdInfo = memo(
  ({ session, isRtl }: { session: SessionData; isRtl: boolean }) => {
    const { t } = useTranslation();
    return (
      <div className={`flex flex-col ${isRtl ? "items-end" : "items-start"}`}>
        <h3 className="text-lg text-white/80">
          {t("session popup - session id")}:
        </h3>
        <h1 className="text-5xl font-extrabold tracking-widest text-white">
          {session.shortid}
        </h1>
      </div>
    );
  },
);

const InstructionsText = memo(
  ({
    iconQuizEnabled,
    isRtl,
  }: {
    iconQuizEnabled: boolean;
    isRtl: boolean;
  }) => {
    const { t } = useTranslation();
    if (iconQuizEnabled) {
      return (
        <div className={isRtl ? "text-right" : ""}>
          <h3 className="text-lg text-white/80">
            {t("session popup - scan the code or go to")}:
          </h3>
          <h1 className="text-3xl font-bold">
            <span className="underline text-blue-200">GoEZ.me</span>
          </h1>
        </div>
      );
    }
    return (
      <div className={isRtl ? "text-right" : ""}>
        <h3 className="text-lg text-white/80">
          {t("session popup - scan the code using app #1")}
        </h3>
        <h3 className="text-lg text-white/80 mt-2">
          {t("session popup - scan the code using app #2")}
        </h3>
      </div>
    );
  },
);

const Instructions = memo(
  ({
    session,
    iconQuizEnabled = true,
    ivrEnabled,
    isRtl,
  }: {
    session: SessionData;
    iconQuizEnabled?: boolean;
    ivrEnabled?: boolean;
    isRtl: boolean;
  }) => {
    return (
      <div className="bg-amber-400 text-gray-900 py-4 px-6 flex items-center justify-between gap-4">
        <div className="flex-1 space-y-1">
          <InstructionsText iconQuizEnabled={iconQuizEnabled} isRtl={isRtl} />
          <IvrInstructions ivrEnabled={ivrEnabled} isRtl={isRtl} />
        </div>
        <SessionIdInfo session={session} isRtl={isRtl} />
      </div>
    );
  },
);

// ---------------------------------------------------------------------------
// StudentsCounter
// ---------------------------------------------------------------------------

const StudentsCounter = memo(
  ({
    visibleAttendeeName,
    isWaiting,
    initialCount,
    nameCounter,
    visibleText,
  }: {
    visibleAttendeeName?: string;
    isWaiting: boolean;
    initialCount: number;
    nameCounter: number;
    visibleText?: string;
  }) => {
    const { t } = useTranslation();
    const total = Number(initialCount) + Number(nameCounter);
    const isVisible =
      !!visibleAttendeeName || (isWaiting && !visibleAttendeeName);
    const [displayed, setDisplayed] = useState(total);

    // Animate counter
    useEffect(() => {
      if (displayed === total) return;
      const step = total > displayed ? 1 : -1;
      const timer = setInterval(() => {
        setDisplayed((prev) => {
          const next = prev + step;
          if ((step > 0 && next >= total) || (step < 0 && next <= total)) {
            clearInterval(timer);
            return total;
          }
          return next;
        });
      }, 50);
      return () => clearInterval(timer);
    }, [total, displayed]);

    return (
      <div className="text-center py-6 text-white">
        {isVisible && visibleText && (
          <h1
            className="text-3xl font-bold animate-in slide-in-from-left duration-500"
            key={visibleText}
          >
            {visibleText}
          </h1>
        )}
        <h2 className="text-xl mt-2">
          {total === 1 ? (
            t("session popup - students checked in single")
          ) : (
            <>
              <span className="font-bold tabular-nums">{displayed}</span>{" "}
              {t("session popup - students checked in")}
            </>
          )}
        </h2>
      </div>
    );
  },
);

// ---------------------------------------------------------------------------
// InfoPane
// ---------------------------------------------------------------------------

export function InfoPane({
  session,
  visibleAttendeeName,
  initialCount,
  nameCounter,
  isWaiting,
  visibleText,
  iconQuizEnabled = true,
  ivrEnabled,
}: InfoPaneProps) {
  const isRtl = session.language === "he";

  return (
    <div
      className="flex flex-col flex-1 bg-[#1a237e] text-white"
      dir={isRtl ? "rtl" : "ltr"}
    >
      {/* Theme logo */}
      {session.theme?.image && (
        <div className="p-4 flex justify-center">
          <img
            src={session.theme.image}
            alt="theme logo"
            className="max-h-20 object-contain"
          />
        </div>
      )}

      {/* Course + Session name */}
      <div className="text-center px-4 py-6">
        <h1 className="text-3xl font-bold">{session.coursename}</h1>
        <h2 className="text-xl text-white/80 mt-1">{session.name}</h2>
      </div>

      {/* Yellow instructions strip */}
      <Instructions
        session={session}
        iconQuizEnabled={iconQuizEnabled}
        ivrEnabled={ivrEnabled}
        isRtl={isRtl}
      />

      {/* Students counter */}
      <StudentsCounter
        visibleAttendeeName={visibleAttendeeName}
        isWaiting={isWaiting}
        initialCount={initialCount}
        nameCounter={nameCounter}
        visibleText={visibleText}
      />
    </div>
  );
}

/**
 * Session store (Zustand).
 * Replaces sessions reducer from Redux (redux-store.md §3.2).
 * Manages session list, lifecycle, navigation, and check-in operations.
 */

import { create } from "zustand";
import { handleError } from "@/shared/utils/error.utils";
import type { Session, CheckinPayload } from "@/shared/types";
import * as sessionService from "@/shared/services/session.service";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface SessionState {
  courseId: string | null;
  sessionId: string | null;
  sessions: Session[];
  session: Session | null;
  nextSession: boolean;
  prevSession: boolean;
  loading: boolean;
}

interface SessionActions {
  // CRUD / Lifecycle
  getCourseSessions: (courseId: string) => Promise<void>;
  createSession: (props: Record<string, unknown>) => Promise<Session>;
  createFutureSession: (props: Record<string, unknown>) => Promise<Session>;
  resumeSession: (
    props: Record<string, unknown>,
    courseId: string,
    sessionId: string,
  ) => Promise<Session>;
  endSession: (courseId: string, sessionId: string) => Promise<void>;
  deleteSession: (courseId: string, sessionId: string) => Promise<void>;
  renameSession: (
    courseId: string,
    sessionId: string,
    name: string,
  ) => Promise<void>;
  updateSession: (
    courseId: string,
    sessionId: string,
    data: Record<string, unknown>,
  ) => Promise<void>;

  // Selection / Navigation
  selectSession: (courseId: string, sessionId: string) => void;
  navigateSession: (direction: "next" | "prev") => void;

  // Check-in
  checkUncheck: (payload: CheckinPayload) => Promise<void>;

  // Reset
  reset: () => void;
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function computePrevNext(sessions: Session[], sessionId: string | null) {
  if (!sessionId || sessions.length === 0) {
    return { nextSession: false, prevSession: false };
  }
  const idx = sessions.findIndex((s) => s.id === sessionId);
  return {
    nextSession: idx < sessions.length - 1,
    prevSession: idx > 0,
  };
}

// ---------------------------------------------------------------------------
// Initial state
// ---------------------------------------------------------------------------

const initialState: SessionState = {
  courseId: null,
  sessionId: null,
  sessions: [],
  session: null,
  nextSession: false,
  prevSession: false,
  loading: false,
};

// ---------------------------------------------------------------------------
// Store
// ---------------------------------------------------------------------------

export const useSessionStore = create<SessionState & SessionActions>()(
  (set, get) => ({
    ...initialState,

    getCourseSessions: async (courseId) => {
      set({ loading: true });
      try {
        const raw = await sessionService.getCourseSessions(courseId);
        // Sort by date descending (newest first), matching legacy display order
        raw.sort((a: any, b: any) => {
          const aDate = a.begins ? new Date(a.begins).getTime() : 0;
          const bDate = b.begins ? new Date(b.begins).getTime() : 0;
          return bDate - aDate;
        });
        // Map API fields and add computed values
        const sessions = raw.map((s: any, i: number) => {
          const checkins = s.checkins ?? 0;
          const totalStudents = s.totalStudents ?? 0;
          return {
            ...s,
            // API returns 'shortid' lowercase — map to camelCase
            shortId: s.shortId || s.shortid || s.id,
            serialId: raw.length - i,
            // Compute attendance rate if not provided
            attendanceRate:
              s.attendanceRate ??
              (totalStudents > 0
                ? Math.round((checkins / totalStudents) * 100)
                : 0),
          } as Session;
        });
        set({ sessions, courseId, loading: false });
      } catch (error) {
        handleError(error, "sessions.getCourseSessions", { message: "Failed to load sessions" });
        set({ sessions: [], loading: false });
      }
    },

    createSession: async (props) => {
      const session = await sessionService.createSession(props);
      // Store session info in localStorage for cross-tab persistence
      sessionService.saveSessionData({
        sessionId: session.id,
        courseId: session.courseId,
        mode: session.mode,
      });
      set({ session, sessionId: session.id, courseId: session.courseId });
      return session;
    },

    createFutureSession: async (props) => {
      const session = await sessionService.createFutureSession(props);
      // Refresh sessions list
      await get().getCourseSessions(session.courseId);
      return session;
    },

    resumeSession: async (props, courseId, sessionId) => {
      const session = await sessionService.resumeSession(
        props,
        courseId,
        sessionId,
      );
      sessionService.saveSessionData({
        sessionId: session.id,
        courseId: session.courseId,
        mode: session.mode,
      });
      set({ session, sessionId: session.id, courseId: session.courseId });
      return session;
    },

    endSession: async (courseId, sessionId) => {
      await sessionService.endSession(courseId, sessionId);
      sessionService.clearSessionStorageInfoForMinimized();
      set({ session: null, sessionId: null });
      // Refresh sessions list
      await get().getCourseSessions(courseId);
    },

    deleteSession: async (courseId, sessionId) => {
      await sessionService.deleteSession(courseId, sessionId);
      set({ session: null, sessionId: null });
      await get().getCourseSessions(courseId);
    },

    renameSession: async (courseId, sessionId, name) => {
      await sessionService.renameSession(courseId, sessionId, name);
      await get().getCourseSessions(courseId);
    },

    updateSession: async (_courseId, sessionId, data) => {
      // Optimistic update — patch local state immediately to avoid skeleton flash
      set((state) => ({
        sessions: state.sessions.map((s) =>
          s.id === sessionId ? { ...s, ...data } : s,
        ),
      }));
      await sessionService.updateSessionData(data, sessionId);
    },

    selectSession: (courseId, sessionId) => {
      const { sessions } = get();
      const session = sessions.find((s) => s.id === sessionId) ?? null;
      const { nextSession, prevSession } = computePrevNext(sessions, sessionId);
      set({ courseId, sessionId, session, nextSession, prevSession });
    },

    navigateSession: (direction) => {
      const { sessions, sessionId } = get();
      if (!sessionId) return;
      const idx = sessions.findIndex((s) => s.id === sessionId);
      const newIdx = direction === "next" ? idx + 1 : idx - 1;
      if (newIdx >= 0 && newIdx < sessions.length) {
        const newSession = sessions[newIdx];
        const { nextSession, prevSession } = computePrevNext(
          sessions,
          newSession.id,
        );
        set({
          sessionId: newSession.id,
          session: newSession,
          nextSession,
          prevSession,
        });
      }
    },

    checkUncheck: async (payload) => {
      await sessionService.checkUncheck(payload);
    },

    reset: () => set(initialState),
  }),
);

/**
 * Features/Latest Blog Posts section — matches legacy LatestPosts component.
 * Fetches blog posts from WordPress REST API (same as legacy).
 * Carousel with left/right arrow navigation matching old app exactly.
 */

import { useEffect, useState, useCallback, useRef } from "react";
import { cn } from "@/lib/utils";
import { Skeleton } from "@/components/ui/skeleton";
import { Link } from "@tanstack/react-router";
import { ChevronLeft, ChevronRight } from "lucide-react";

const WP_API_URL = "https://postsapi.ezcheck.me/wp-json/wp/v2";

interface WPPost {
  id: number;
  slug: string;
  title: { rendered: string };
  _embedded?: {
    "wp:featuredmedia"?: Array<{
      media_details?: {
        sizes?: {
          medium?: { source_url: string };
          full?: { source_url: string };
        };
      };
      source_url?: string;
    }>;
  };
}

interface DisplayPost {
  id: string;
  slug: string;
  title: string;
  coverImage: string;
}

const FALLBACK_POSTS: DisplayPost[] = [
  {
    id: "fallback-1",
    slug: "post-checkin-messages",
    title: "Introducing EZCheck.me's New Feature: Post Check-in Messages!",
    coverImage:
      "https://placehold.co/600x400/e8f5e9/2e7d32?text=Post+Check-in+Messages",
  },
  {
    id: "fallback-2",
    slug: "qwickly-partnership",
    title:
      "Qwickly Leads the Way in Transforming Attendance Tracking with New Partnership with EZCheck.me",
    coverImage:
      "https://placehold.co/600x400/e3f2fd/1565c0?text=Qwickly+Partnership",
  },
  {
    id: "fallback-3",
    slug: "clinical-rotations",
    title:
      "Revolutionizing Clinical Rotations: Introducing EZCheck.me Seamless Clinical Rotation Attendance Tracking",
    coverImage:
      "https://placehold.co/600x400/fff3e0/e65100?text=Clinical+Rotations",
  },
];

function parseWPPost(post: WPPost): DisplayPost {
  let coverImage = "";
  if (post._embedded?.["wp:featuredmedia"]?.[0]) {
    const media = post._embedded["wp:featuredmedia"][0];
    coverImage =
      media.media_details?.sizes?.medium?.source_url ||
      media.media_details?.sizes?.full?.source_url ||
      media.source_url ||
      "";
  }
  const div = document.createElement("div");
  div.innerHTML = post.title.rendered;
  const title = div.textContent || post.title.rendered;

  return {
    id: String(post.id),
    slug: post.slug,
    title,
    coverImage,
  };
}

export function FeaturesSection() {
  const [allPosts, setAllPosts] = useState<DisplayPost[]>([]);
  const [visiblePosts, setVisiblePosts] = useState<DisplayPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [imagesLoaded, setImagesLoaded] = useState(false);
  const [animating, setAnimating] = useState(false);
  const [animateDir, setAnimateDir] = useState<"left" | "right">("right");
  const indexRef = useRef(0);
  const imagesLoadedCount = useRef(0);
  const animationTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetch(`${WP_API_URL}/posts?per_page=12&_embed`)
      .then((r) => r.json())
      .then((data: WPPost[]) => {
        if (Array.isArray(data) && data.length > 0) {
          const parsed = data.map(parseWPPost);
          setAllPosts(parsed);
          setVisiblePosts(parsed.slice(0, 3));
          indexRef.current = 0;
        } else {
          setAllPosts(FALLBACK_POSTS);
          setVisiblePosts(FALLBACK_POSTS);
        }
      })
      .catch((err) => {
        console.error("Failed to fetch blog posts:", err);
        setAllPosts(FALLBACK_POSTS);
        setVisiblePosts(FALLBACK_POSTS);
      })
      .finally(() => setLoading(false));
  }, []);

  const onArrowClick = useCallback(
    (direction: number) => {
      if (!imagesLoaded || allPosts.length === 0) return;

      if (animationTimer.current) clearTimeout(animationTimer.current);
      setAnimateDir(direction < 0 ? "left" : "right");
      setAnimating(true);

      animationTimer.current = setTimeout(() => {
        setAnimating(false);
      }, 400);

      setTimeout(() => {
        const step = direction * 3;
        let newIndex =
          (indexRef.current + step + allPosts.length * 10) % allPosts.length;
        indexRef.current = newIndex;

        const updated: DisplayPost[] = [];
        for (let i = 0; i < 3; i++) {
          updated.push(allPosts[(newIndex + i) % allPosts.length]);
        }
        setVisiblePosts(updated);
      }, 200);
    },
    [allPosts, imagesLoaded],
  );

  const onImageLoad = useCallback(() => {
    imagesLoadedCount.current += 1;
    if (imagesLoadedCount.current >= 3) {
      setImagesLoaded(true);
    }
  }, []);

  return (
    <section id="features" className="relative pt-8 bg-white">
      <div className="mx-auto max-w-6xl px-6">
        {loading ? (
          <div className="flex gap-6 justify-between mb-12">
            {Array.from({ length: 3 }).map((_, i) => (
              <div
                key={i}
                className="flex flex-col bg-white overflow-hidden rounded-xl"
                style={{ width: "31%" }}
              >
                <Skeleton height={200} borderRadius={10} />
                <div className="p-6 space-y-3 flex flex-col items-center">
                  <Skeleton width="85%" height={16} borderRadius={3} />
                  <Skeleton width="60%" height={14} borderRadius={3} />
                </div>
              </div>
            ))}
          </div>
        ) : (
          visiblePosts.length > 0 && (
            <div className="relative mb-12">
              {/* Left Arrow */}
              <button
                onClick={() => onArrowClick(-1)}
                className="absolute z-10 flex items-center justify-center cursor-pointer transition-opacity hover:opacity-80"
                style={{
                  top: 89,
                  left: -19,
                  width: 32,
                  height: 32,
                  background: "#000",
                  color: "#fff",
                  border: "3px solid white",
                  borderRadius: 26,
                }}
                aria-label="Previous posts"
              >
                <ChevronLeft className="h-5 w-5" />
              </button>

              {/* Right Arrow */}
              <button
                onClick={() => onArrowClick(1)}
                className="absolute z-10 flex items-center justify-center cursor-pointer transition-opacity hover:opacity-80"
                style={{
                  top: 89,
                  right: -19,
                  width: 32,
                  height: 32,
                  background: "#000",
                  color: "#fff",
                  border: "3px solid white",
                  borderRadius: 26,
                }}
                aria-label="Next posts"
              >
                <ChevronRight className="h-5 w-5" />
              </button>

              {/* Cards container with animation */}
              <div className="w-full overflow-hidden">
                <div
                  className={cn(
                    "flex justify-between w-full transition-all",
                    animating && animateDir === "left" && "animate-bounce-out-right",
                    animating && animateDir === "right" && "animate-bounce-out-left",
                    !animating && "animate-fade-in",
                  )}
                  style={{
                    animationDuration: "400ms",
                    animationFillMode: "both",
                  }}
                >
                  {visiblePosts.map((post) => {
                    const imageUrl =
                      post.coverImage ||
                      "https://placehold.co/600x400/f3f4f6/9ca3af?text=EzCheck.me";

                    return (
                      <Link
                        key={post.id}
                        to="/blog/$id"
                        params={{ id: post.slug || post.id }}
                        className="flex flex-col bg-white overflow-hidden cursor-pointer"
                        style={{ width: "31%" }}
                      >
                        <div
                          className="w-full overflow-hidden relative"
                          style={{ borderRadius: 10 }}
                        >
                          <img
                            src={imageUrl}
                            alt={post.title}
                            onError={(e) => {
                              e.currentTarget.src =
                                "https://placehold.co/600x400/f3f4f6/9ca3af?text=EzCheck.me";
                            }}
                            onLoad={onImageLoad}
                            className="w-full aspect-video object-cover"
                            style={{
                              display: imagesLoaded ? "block" : "none",
                              borderRadius: 10,
                            }}
                          />
                          {/* Placeholder while images load */}
                          {!imagesLoaded && (
                            <div
                              className="w-full aspect-video"
                              style={{
                                backgroundColor: "#eeeeee",
                                borderRadius: 10,
                              }}
                            />
                          )}
                        </div>
                        <div className="py-4 px-2">
                          <h3
                            className="leading-snug"
                            style={{
                              textAlign: "center",
                              minHeight: 80,
                              fontWeight: 600,
                              fontSize: 17,
                              color: imagesLoaded ? "#000" : "#fff",
                            }}
                          >
                            {imagesLoaded ? post.title : "title"}
                          </h3>
                        </div>
                      </Link>
                    );
                  })}
                </div>
              </div>
            </div>
          )
        )}
      </div>

      {/* Animation keyframes */}
      <style>{`
        @keyframes bounceOutLeft {
          0% { transform: translateX(0); opacity: 1; }
          100% { transform: translateX(-30px); opacity: 0; }
        }
        @keyframes bounceOutRight {
          0% { transform: translateX(0); opacity: 1; }
          100% { transform: translateX(30px); opacity: 0; }
        }
        @keyframes fadeIn {
          0% { opacity: 0; }
          100% { opacity: 1; }
        }
        .animate-bounce-out-left {
          animation-name: bounceOutLeft;
        }
        .animate-bounce-out-right {
          animation-name: bounceOutRight;
        }
        .animate-fade-in {
          animation-name: fadeIn;
          animation-duration: 300ms;
        }
      `}</style>
    </section>
  );
}

